// index.ts — Main entry: IWSDK world, game loop, state machine, UI binding
import { World, PanelUI, Follower, FollowBehavior, ScreenSpace, PanelDocument } from '@iwsdk/core';
import type { UIKitDocument } from '@iwsdk/core';
import * as THREE from 'three';
import {
  GameStateManager, GameState, LEVELS, TILE, THEMES, ACHIEVEMENTS,
  BOARD_CELL, MARBLE_RADIUS, MAX_TILT, TILT_SPEED, GRAVITY,
  FRICTION, ICE_FRICTION, BOUNCE_DAMP, BOOST_IMPULSE, MARBLE_MAX_SPEED,
  addLeaderboard, getLeaderboard, getDailySeed, seededRandom,
  calcStars, MARBLE_SKINS, getLevelZone, ZONE_NAMES,
} from './types.js';
import { buildBoard, gridToLocal, getTileAt, checkWallCollision, animateBoard, BoardObjects } from './board.js';
import { AudioManager } from './audio.js';
import { ParticleSystem, TrailSystem, AmbientParticles, createHolodeckDecorations, animateDecorations } from './effects.js';

// ============================================================
// IWSDK World Init
// ============================================================
const container = document.getElementById('app') as HTMLDivElement;
const world = await World.create(container, {
  xr: { offer: 'once' },
  features: { spatialUI: true },
});

const scene = world.scene;

// ============================================================
// Game State
// ============================================================
const gsm = new GameStateManager();
const audio = new AudioManager();

let board: BoardObjects | null = null;
let boardEntity: THREE.Group | null = null;
let marbleMesh: THREE.Mesh | null = null;
let marbleGlow: THREE.Mesh | null = null;
let marbleVel = new THREE.Vector2(0, 0);
let marblePos = new THREE.Vector3(0, 0, 0);
let boardTilt = new THREE.Vector2(0, 0);   // current tilt x, z
let targetTilt = new THREE.Vector2(0, 0);  // target from input
let particles: ParticleSystem | null = null;
let trail: TrailSystem | null = null;
let ambientParticles: AmbientParticles | null = null;
let decos: THREE.Object3D[] = [];
let countdownTimer = 0;
let countdownPhase = 0;
let onIce = false;
let rollSoundTimer = 0;
let teleCooldown = 0;
let lastTime = performance.now();
let magnetPullTimer = 0;
let shieldMesh: THREE.Mesh | null = null;
let magnetGems = 0; // gems collected while magnet active
const COMBO_WINDOW = 2.0; // seconds to chain gems

// Input state
const keys: Record<string, boolean> = {};
window.addEventListener('keydown', e => { keys[e.key.toLowerCase()] = true; });
window.addEventListener('keyup', e => { keys[e.key.toLowerCase()] = false; });

// ============================================================
// Lighting & Environment
// ============================================================
scene.fog = new THREE.FogExp2(0x000811, 0.25);
const ambLight = new THREE.AmbientLight(0x222244, 0.5);
scene.add(ambLight);
const dirLight = new THREE.DirectionalLight(0xffffff, 0.6);
dirLight.position.set(2, 4, 1);
scene.add(dirLight);
const ptLight1 = new THREE.PointLight(0x00ffff, 0.8, 5);
ptLight1.position.set(-1, 2, -1);
scene.add(ptLight1);
const ptLight2 = new THREE.PointLight(0xff3366, 0.4, 5);
ptLight2.position.set(1, 2, 1);
scene.add(ptLight2);

// Holodeck grid floor
const gridFloorGeo = new THREE.PlaneGeometry(8, 8);
const gridFloorMat = new THREE.MeshStandardMaterial({
  color: 0x040410,
  roughness: 0.8,
  metalness: 0.2,
});
const gridFloor = new THREE.Mesh(gridFloorGeo, gridFloorMat);
gridFloor.rotation.x = -Math.PI / 2;
gridFloor.position.y = -0.01;
scene.add(gridFloor);

// Neon grid on floor
const neonGridMat = new THREE.LineBasicMaterial({ color: 0x00ffff, transparent: true, opacity: 0.08 });
for (let i = -4; i <= 4; i++) {
  const pts1 = [new THREE.Vector3(i, 0.001, -4), new THREE.Vector3(i, 0.001, 4)];
  const pts2 = [new THREE.Vector3(-4, 0.001, i), new THREE.Vector3(4, 0.001, i)];
  scene.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(pts1), neonGridMat));
  scene.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(pts2), neonGridMat));
}

// Ceiling grid
const ceilGridMat = new THREE.LineBasicMaterial({ color: 0x00ffff, transparent: true, opacity: 0.04 });
for (let i = -4; i <= 4; i++) {
  const pts1 = [new THREE.Vector3(i, 3, -4), new THREE.Vector3(i, 3, 4)];
  const pts2 = [new THREE.Vector3(-4, 3, i), new THREE.Vector3(4, 3, i)];
  scene.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(pts1), ceilGridMat));
  scene.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(pts2), ceilGridMat));
}

ambientParticles = new AmbientParticles(scene, 40, 4);
decos = createHolodeckDecorations(scene, 14);

// ============================================================
// UI Panel Entities
// ============================================================
type PanelName = 'title' | 'modeselect' | 'levelselect' | 'hud' | 'pause' | 'levelcomplete'
  | 'gameover' | 'leaderboard' | 'achievements' | 'settings' | 'help' | 'toast' | 'countdown'
  | 'stats' | 'skins' | 'speedrun';

const panels: Map<PanelName, { entity: any; doc: UIKitDocument | null }> = new Map();

function createPanel(name: PanelName, config: string, opts: {
  maxWidth?: number; maxHeight?: number;
  follower?: boolean; screenSpace?: boolean;
  offsetPos?: [number, number, number];
  worldPos?: [number, number, number];
}) {
  const entity = world.createTransformEntity(undefined, { persistent: true });
  entity.addComponent(PanelUI, {
    config,
    maxWidth: opts.maxWidth || 0.8,
    maxHeight: opts.maxHeight || 1.0,
  });
  if (opts.follower) {
    entity.addComponent(Follower, {
      target: world.player.head,
      offsetPosition: opts.offsetPos || [0, 0, -0.6],
      behavior: FollowBehavior.PivotY,
      speed: 5,
      tolerance: 0.3,
    });
  } else if (opts.worldPos) {
    entity.object3D!.position.set(...opts.worldPos);
  }
  if (opts.screenSpace) {
    entity.addComponent(ScreenSpace, {
      width: '50vw', height: 'auto', bottom: '10vh', left: '25vw', zOffset: 0.2,
    });
  }
  panels.set(name, { entity, doc: null });
}

// Create all panels
createPanel('title', '/ui/title.json', { maxWidth: 0.9, maxHeight: 0.7, worldPos: [0, 1.5, -2] });
createPanel('modeselect', '/ui/modeselect.json', { maxWidth: 0.8, maxHeight: 0.7, worldPos: [0, 1.5, -2] });
createPanel('levelselect', '/ui/levelselect.json', { maxWidth: 0.9, maxHeight: 0.8, worldPos: [0, 1.5, -2] });
createPanel('hud', '/ui/hud.json', { maxWidth: 0.35, maxHeight: 0.12, follower: true, offsetPos: [0.25, 0.15, -0.5] });
createPanel('pause', '/ui/pause.json', { maxWidth: 0.6, maxHeight: 0.5, worldPos: [0, 1.5, -1.8] });
createPanel('levelcomplete', '/ui/levelcomplete.json', { maxWidth: 0.7, maxHeight: 0.6, worldPos: [0, 1.5, -1.8] });
createPanel('gameover', '/ui/gameover.json', { maxWidth: 0.7, maxHeight: 0.5, worldPos: [0, 1.5, -1.8] });
createPanel('leaderboard', '/ui/leaderboard.json', { maxWidth: 0.8, maxHeight: 0.8, worldPos: [0, 1.5, -2] });
createPanel('achievements', '/ui/achievements.json', { maxWidth: 0.8, maxHeight: 0.8, worldPos: [0, 1.5, -2] });
createPanel('settings', '/ui/settings.json', { maxWidth: 0.7, maxHeight: 0.7, worldPos: [0, 1.5, -2] });
createPanel('help', '/ui/help.json', { maxWidth: 0.8, maxHeight: 0.7, worldPos: [0, 1.5, -2] });
createPanel('toast', '/ui/toast.json', { maxWidth: 0.3, maxHeight: 0.08, follower: true, offsetPos: [0, -0.2, -0.5] });
createPanel('countdown', '/ui/countdown.json', { maxWidth: 0.3, maxHeight: 0.15, follower: true, offsetPos: [0, 0, -0.5] });
createPanel('stats', '/ui/stats.json', { maxWidth: 0.8, maxHeight: 0.8, worldPos: [0, 1.5, -2] });
createPanel('skins', '/ui/skins.json', { maxWidth: 0.7, maxHeight: 0.6, worldPos: [0, 1.5, -2] });
createPanel('speedrun', '/ui/speedrun.json', { maxWidth: 0.8, maxHeight: 0.8, worldPos: [0, 1.5, -2] });

// ============================================================
// UI Helpers
// ============================================================
function getDoc(name: PanelName): UIKitDocument | null {
  const p = panels.get(name);
  if (!p) return null;
  if (!p.doc) {
    p.doc = p.entity.getValue(PanelDocument, 'document') as UIKitDocument | null;
  }
  return p.doc;
}

function setText(name: PanelName, id: string, text: string) {
  const doc = getDoc(name);
  if (!doc) return;
  const el = doc.getElementById(id);
  if (el) (el as any).text.value = text;
}

function showPanel(name: PanelName | 'playing') {
  panels.forEach((p, n) => {
    p.entity.object3D.visible = n === name || (name === 'playing' && n === 'hud');
  });
  // HUD is always visible during play
  if (name === 'playing') {
    const hudP = panels.get('hud');
    if (hudP) hudP.entity.object3D.visible = true;
  }
}

function showUI(state: GameState) {
  // Hide all panels first
  panels.forEach(p => { p.entity.object3D.visible = false; });

  switch (state) {
    case 'title':
      panels.get('title')!.entity.object3D.visible = true;
      break;
    case 'modeselect':
      panels.get('modeselect')!.entity.object3D.visible = true;
      break;
    case 'levelselect':
      updateLevelSelect();
      panels.get('levelselect')!.entity.object3D.visible = true;
      break;
    case 'playing':
      panels.get('hud')!.entity.object3D.visible = true;
      break;
    case 'paused':
      panels.get('hud')!.entity.object3D.visible = true;
      panels.get('pause')!.entity.object3D.visible = true;
      break;
    case 'levelcomplete':
      panels.get('levelcomplete')!.entity.object3D.visible = true;
      break;
    case 'gameover':
      panels.get('gameover')!.entity.object3D.visible = true;
      break;
    case 'leaderboard':
      updateLeaderboardPanel();
      panels.get('leaderboard')!.entity.object3D.visible = true;
      break;
    case 'achievements':
      updateAchievementsPanel();
      panels.get('achievements')!.entity.object3D.visible = true;
      break;
    case 'settings':
      panels.get('settings')!.entity.object3D.visible = true;
      break;
    case 'help':
      panels.get('help')!.entity.object3D.visible = true;
      break;
    case 'stats':
      updateStatsPanel();
      panels.get('stats')!.entity.object3D.visible = true;
      break;
    case 'skins':
      updateSkinsPanel();
      panels.get('skins')!.entity.object3D.visible = true;
      break;
    case 'speedrun':
      updateSpeedrunPanel();
      panels.get('speedrun')!.entity.object3D.visible = true;
      break;
  }
}

let toastTimer = 0;
function showToast(msg: string, dur: number = 2) {
  setText('toast', 'toast-msg', msg);
  const tp = panels.get('toast');
  if (tp) tp.entity.object3D.visible = true;
  toastTimer = dur;
}

function updateHUD() {
  const elapsed = gsm.mode === 'zen' ? 0 : gsm.elapsedTime;
  const mins = Math.floor(elapsed / 60);
  const secs = Math.floor(elapsed % 60);
  setText('hud', 'hud-time', `${mins}:${secs.toString().padStart(2, '0')}`);
  setText('hud', 'hud-gems', `${gsm.gemsCollected}/${gsm.gemsTotal}`);
  setText('hud', 'hud-lives', `${gsm.lives}`);
  setText('hud', 'hud-score', `${gsm.score}`);
  const level = LEVELS[gsm.level] || LEVELS[0];
  setText('hud', 'hud-level', level.name);
  // Power-up indicators
  const puParts: string[] = [];
  if (gsm.shieldActive) puParts.push(`🛡${Math.ceil(gsm.shieldTimer)}s`);
  if (gsm.magnetActive) puParts.push(`🧲${Math.ceil(gsm.magnetTimer)}s`);
  if (gsm.slowmoActive) puParts.push(`⏳${Math.ceil(gsm.slowmoTimer)}s`);
  setText('hud', 'hud-powerups', puParts.join(' '));
  if (gsm.gravityFlipped) {
    setText('hud', 'hud-gravity', '⬆ REVERSED');
  } else {
    setText('hud', 'hud-gravity', '');
  }
  // Combo display
  if (gsm.comboCount >= 2) {
    setText('hud', 'hud-combo', `${gsm.comboCount}x COMBO`);
  } else {
    setText('hud', 'hud-combo', '');
  }
  // Speed run split delta display
  if (gsm.speedrunActive && gsm.mode === 'campaign') {
    const pbSplit = gsm.bestCampaignSplits[gsm.level];
    if (pbSplit !== null) {
      const delta = gsm.elapsedTime - pbSplit;
      const sign = delta >= 0 ? '+' : '';
      const color = delta < 0 ? '🟢' : '🔴';
      setText('hud', 'hud-split', `${color} ${sign}${delta.toFixed(1)}s`);
    } else {
      setText('hud', 'hud-split', '');
    }
    // Total run time
    const totalRun = gsm.campaignTotalTime + gsm.elapsedTime;
    const tMins = Math.floor(totalRun / 60);
    const tSecs = Math.floor(totalRun % 60);
    setText('hud', 'hud-runtimer', `RUN ${tMins}:${tSecs.toString().padStart(2, '0')}`);
  } else {
    setText('hud', 'hud-split', '');
    setText('hud', 'hud-runtimer', '');
  }
  // Zone indicator
  const zone = getLevelZone(gsm.level);
  setText('hud', 'hud-zone', ZONE_NAMES[zone] || '');
}

function updateLevelSelect() {
  for (let i = 0; i < 36; i++) {
    const cleared = gsm.campaignProgress[i] || false;
    const best = gsm.bestTimes[i];
    const stars = gsm.starRatings[i] || 0;
    const label = i < LEVELS.length ? LEVELS[i].name : `Level ${i + 1}`;
    const starStr = stars > 0 ? '★'.repeat(stars) + '☆'.repeat(3 - stars) : '';
    setText('levelselect', `lvl-name-${i}`, label);
    setText('levelselect', `lvl-status-${i}`, cleared ? (best ? `${best.toFixed(1)}s ${starStr}` : `Cleared ${starStr}`) : '---');
  }
}

function updateLeaderboardPanel() {
  const lb = getLeaderboard();
  for (let i = 0; i < 10; i++) {
    const e = lb[i];
    setText('leaderboard', `lb-rank-${i}`, e ? `${i + 1}` : '');
    setText('leaderboard', `lb-name-${i}`, e ? e.level : '');
    setText('leaderboard', `lb-score-${i}`, e ? `${e.score}` : '');
    setText('leaderboard', `lb-time-${i}`, e ? `${e.time.toFixed(1)}s` : '');
  }
}

function updateAchievementsPanel() {
  for (let i = 0; i < ACHIEVEMENTS.length; i++) {
    const a = ACHIEVEMENTS[i];
    const unlocked = gsm.unlockedAchievements.has(a.id);
    setText('achievements', `ach-name-${i}`, unlocked ? a.name : '???');
    setText('achievements', `ach-desc-${i}`, unlocked ? a.desc : 'Locked');
  }
}

function updateStatsPanel() {
  setText('stats', 'stat-clears', `${gsm.totalClears}`);
  setText('stats', 'stat-gems', `${gsm.totalGems}`);
  setText('stats', 'stat-deaths', `${gsm.totalDeaths}`);
  setText('stats', 'stat-perfect', `${gsm.perfectLevels}`);
  setText('stats', 'stat-fastest', gsm.fastestClear < Infinity ? `${gsm.fastestClear.toFixed(1)}s` : '---');
  setText('stats', 'stat-streak', `${gsm.longestStreak}`);
  setText('stats', 'stat-playtime', formatPlayTime(gsm.totalPlayTime));
  setText('stats', 'stat-powerups', `${gsm.powerupsCollected}`);
  setText('stats', 'stat-shields', `${gsm.shieldsUsed}`);
  const totalStars = gsm.starRatings.reduce((a, b) => a + b, 0);
  setText('stats', 'stat-stars', `${totalStars}/${LEVELS.length * 3}`);
  const progress = gsm.campaignProgress.filter(Boolean).length;
  setText('stats', 'stat-progress', `${progress}/${LEVELS.length}`);
  setText('stats', 'stat-achievements', `${gsm.unlockedAchievements.size}/${ACHIEVEMENTS.length}`);
  setText('stats', 'stat-bumpers', `${gsm.bumpersHit}`);
  setText('stats', 'stat-combo', `${gsm.maxCombo}x`);
  setText('stats', 'stat-survival', `${gsm.survivalBestRun} levels`);
}

function formatPlayTime(seconds: number): string {
  const hrs = Math.floor(seconds / 3600);
  const mins = Math.floor((seconds % 3600) / 60);
  if (hrs > 0) return `${hrs}h ${mins}m`;
  return `${mins}m`;
}

function updateSkinsPanel() {
  for (let i = 0; i < MARBLE_SKINS.length; i++) {
    const skin = MARBLE_SKINS[i];
    const selected = i === gsm.currentSkin;
    setText('skins', `skin-name-${i}`, skin.name);
    setText('skins', `skin-status-${i}`, selected ? '● EQUIPPED' : '○ Select');
  }
  // Clear extra slots if panel has more
  for (let i = MARBLE_SKINS.length; i < 10; i++) {
    setText('skins', `skin-name-${i}`, '');
    setText('skins', `skin-status-${i}`, '');
  }
}

function updateSpeedrunPanel() {
  // Total time
  if (gsm.campaignSplits.length > 0) {
    const total = gsm.campaignSplits.reduce((a, b) => a + b, 0);
    setText('speedrun', 'sr-total-time', formatSplitTime(total));
  } else {
    setText('speedrun', 'sr-total-time', '--:--');
  }

  // PB total
  if (gsm.bestCampaignTotal !== null) {
    setText('speedrun', 'sr-pb-total', formatSplitTime(gsm.bestCampaignTotal));
  } else {
    setText('speedrun', 'sr-pb-total', '---');
  }

  // Individual splits (show up to 12)
  for (let i = 0; i < 12; i++) {
    if (i < gsm.campaignSplits.length) {
      const levelName = i < LEVELS.length ? LEVELS[i].name : `Level ${i + 1}`;
      const splitTime = gsm.campaignSplits[i];
      const pbSplit = gsm.bestCampaignSplits[i];

      setText('speedrun', `sr-name-${i}`, levelName);
      setText('speedrun', `sr-time-${i}`, formatSplitTime(splitTime));

      // Delta vs PB
      if (pbSplit !== null) {
        const delta = splitTime - pbSplit;
        const sign = delta >= 0 ? '+' : '';
        setText('speedrun', `sr-delta-${i}`, `${sign}${delta.toFixed(1)}s`);
      } else {
        setText('speedrun', `sr-delta-${i}`, 'NEW');
      }
    } else if (i < LEVELS.length && gsm.bestCampaignSplits[i] !== null) {
      // Show PB splits for levels not yet completed in this run
      setText('speedrun', `sr-name-${i}`, LEVELS[i].name);
      setText('speedrun', `sr-time-${i}`, '---');
      setText('speedrun', `sr-delta-${i}`, `PB: ${formatSplitTime(gsm.bestCampaignSplits[i]!)}`);
    } else {
      setText('speedrun', `sr-name-${i}`, '---');
      setText('speedrun', `sr-time-${i}`, '---');
      setText('speedrun', `sr-delta-${i}`, '');
    }
  }
}

function formatSplitTime(seconds: number): string {
  const mins = Math.floor(seconds / 60);
  const secs = Math.floor(seconds % 60);
  const ms = Math.floor((seconds % 1) * 10);
  if (mins > 0) return `${mins}:${secs.toString().padStart(2, '0')}.${ms}`;
  return `${secs}.${ms}s`;
}

// ============================================================
// Achievement checking
// ============================================================
function checkAchievements() {
  const newlyUnlocked: string[] = [];

  const check = (id: string, cond: boolean) => {
    if (cond && !gsm.unlockedAchievements.has(id)) {
      gsm.unlockedAchievements.add(id);
      newlyUnlocked.push(id);
    }
  };

  check('first_clear', gsm.totalClears >= 1);
  check('gem_collector', gsm.totalGems >= 10);
  check('gems_25', gsm.totalGems >= 25);
  check('gems_50', gsm.totalGems >= 50);
  check('speed_demon', gsm.elapsedTime < (LEVELS[gsm.level]?.par || 999));
  check('perfect_run', gsm.gemsCollected >= gsm.gemsTotal && gsm.gemsTotal > 0);
  check('no_deaths', gsm.noDeathStreak >= 3);
  check('campaign_half', gsm.campaignProgress.filter(Boolean).length >= 6);
  check('campaign_done', gsm.campaignProgress.filter(Boolean).length >= LEVELS.length);
  check('zen_master', gsm.mode === 'zen' && gsm.state === 'levelcomplete');
  check('time_attack_3', gsm.timeAttackClears >= 3);
  check('daily_3', gsm.dailyCompleted >= 3);
  check('warp_5', gsm.warpsUsed >= 5);
  check('under_10', gsm.elapsedTime < 10);
  check('all_perfect', gsm.perfectLevels >= 6);
  check('falls_0', gsm.totalClears >= LEVELS.length && gsm.totalDeaths === 0);
  check('boost_10', gsm.boostsHit >= 10);
  check('theme_all', gsm.themesUsed.size >= THEMES.length);
  check('streak_3', gsm.streak >= 3);
  check('total_20', gsm.totalClears >= 20);
  check('powerup_first', gsm.powerupsCollected >= 1);
  check('shield_save', gsm.shieldsUsed >= 1);
  check('three_stars', gsm.starRatings.some(s => s >= 3));
  check('all_stars', gsm.starRatings.slice(0, LEVELS.length).every(s => s >= 3));
  check('gems_100', gsm.totalGems >= 100);
  check('magnet_gems', magnetGems >= 5);
  check('slowmo_clear', gsm.slowmoActive && gsm.state === 'levelcomplete');
  check('speed_5', gsm.bestTimes.filter((t, i) => t !== null && t < (LEVELS[i]?.par || 999)).length >= 5);
  check('total_50', gsm.totalClears >= 50);
  check('gravity_master', gsm.level >= 19 && gsm.level <= 23 && gsm.state === 'levelcomplete');
  check('wall_dodger', gsm.level >= 18 && gsm.state === 'levelcomplete' && gsm.lives === 3);
  check('endgame', gsm.campaignProgress[23] === true);
  check('all_24', gsm.campaignProgress.filter(Boolean).length >= 24);
  check('skins_all', gsm.skinsUsed.size >= MARBLE_SKINS.length);
  check('bumper_10', gsm.bumpersHit >= 10);
  check('combo_3', gsm.maxCombo >= 3);
  check('combo_5', gsm.maxCombo >= 5);
  check('total_100', gsm.totalClears >= 100);
  check('all_30', gsm.campaignProgress.filter(Boolean).length >= 30);
  check('master_1', gsm.level >= 30 && gsm.level <= 35 && gsm.state === 'levelcomplete');
  check('master_all', gsm.campaignProgress.slice(30, 36).every(Boolean));
  check('all_36', gsm.campaignProgress.filter(Boolean).length >= 36);
  check('survival_10', gsm.survivalLevelsCleared >= 10 || gsm.survivalBestRun >= 10);
  check('survival_25', gsm.survivalLevelsCleared >= 25 || gsm.survivalBestRun >= 25);

  for (const id of newlyUnlocked) {
    const ach = ACHIEVEMENTS.find(a => a.id === id);
    if (ach) {
      showToast(`Achievement: ${ach.name}!`, 3);
      audio.playAchievement();
    }
  }

  if (newlyUnlocked.length > 0) gsm.save();
}

// ============================================================
// Board / Level Management
// ============================================================
function loadLevel(levelIdx: number) {
  // Clear old board
  if (boardEntity) {
    scene.remove(boardEntity);
    boardEntity = null;
  }
  if (marbleMesh) { scene.remove(marbleMesh); marbleMesh = null; }
  if (marbleGlow) { scene.remove(marbleGlow); marbleGlow = null; }

  const level = LEVELS[levelIdx];
  if (!level) return;

  gsm.level = levelIdx;
  gsm.gemsTotal = level.gems;
  gsm.resetLevel();

  board = buildBoard(level, gsm.currentTheme);
  boardEntity = board.group;
  boardEntity.position.set(0, 1.0, -1.2);  // floating in front of player at table height
  scene.add(boardEntity);

  // Create marble with selected skin
  const theme = THEMES[gsm.currentTheme];
  const skin = MARBLE_SKINS[gsm.currentSkin] || MARBLE_SKINS[0];
  const marbleGeo = new THREE.SphereGeometry(MARBLE_RADIUS, 16, 16);
  const marbleMat = new THREE.MeshStandardMaterial({
    color: skin.color,
    emissive: new THREE.Color(skin.emissive),
    emissiveIntensity: 0.4,
    roughness: 0.2,
    metalness: 0.7,
  });
  marbleMesh = new THREE.Mesh(marbleGeo, marbleMat);
  boardEntity.add(marbleMesh);

  // Marble glow
  marbleGlow = new THREE.Mesh(
    new THREE.SphereGeometry(MARBLE_RADIUS * 1.8, 8, 8),
    new THREE.MeshBasicMaterial({ color: skin.glow, transparent: true, opacity: 0.15 })
  );
  boardEntity.add(marbleGlow);

  // Shield mesh (hidden until active)
  shieldMesh = new THREE.Mesh(
    new THREE.SphereGeometry(MARBLE_RADIUS * 2.5, 12, 12),
    new THREE.MeshBasicMaterial({ color: 0x4488ff, transparent: true, opacity: 0, wireframe: true })
  );
  boardEntity.add(shieldMesh);

  // Place marble at start
  const startLocal = gridToLocal(board.startPos.x, board.startPos.y, board.gridW, board.gridH);
  marblePos.copy(startLocal);
  marbleMesh.position.copy(marblePos);
  marbleGlow.position.copy(marblePos);
  marbleVel.set(0, 0);
  boardTilt.set(0, 0);
  targetTilt.set(0, 0);
  teleCooldown = 0;

  // Reset particles/trail
  if (particles) particles = null;
  particles = new ParticleSystem(boardEntity);
  if (trail) trail = null;
  trail = new TrailSystem(boardEntity, skin.trailColor, skin.trailStyle, skin.trailParticleColor, skin.trailParticleRate, skin.trailWidth);

  // Set music zone based on level
  const zone = getLevelZone(levelIdx);
  audio.setZone(zone);
}

function resetMarble() {
  if (!board || !marbleMesh || !marbleGlow) return;
  const startLocal = gridToLocal(board.startPos.x, board.startPos.y, board.gridW, board.gridH);
  marblePos.copy(startLocal);
  marbleMesh.position.copy(marblePos);
  marbleGlow.position.copy(marblePos);
  if (shieldMesh) shieldMesh.position.copy(marblePos);
  marbleVel.set(0, 0);
  boardTilt.set(0, 0);
  targetTilt.set(0, 0);
  trail?.clear();
}

// ============================================================
// State Transitions
// ============================================================
function changeState(newState: GameState) {
  gsm.state = newState;
  showUI(newState);

  switch (newState) {
    case 'title':
      audio.startMusic();
      if (boardEntity) { scene.remove(boardEntity); boardEntity = null; }
      break;
    case 'playing':
      break;
    case 'paused':
      break;
    case 'levelcomplete': {
      gsm.elapsedTime = (performance.now() - gsm.startTime) / 1000;
      const level = LEVELS[gsm.level];
      const isPerfect = gsm.gemsCollected >= gsm.gemsTotal;
      const underPar = gsm.elapsedTime < level.par;
      gsm.totalClears++;
      gsm.streak++;
      if (gsm.streak > gsm.longestStreak) gsm.longestStreak = gsm.streak;
      gsm.noDeathStreak++;
      if (isPerfect) gsm.perfectLevels++;
      if (gsm.elapsedTime < gsm.fastestClear) gsm.fastestClear = gsm.elapsedTime;
      gsm.totalPlayTime += gsm.elapsedTime;
      if (gsm.mode === 'campaign') {
        gsm.campaignProgress[gsm.level] = true;
        const bt = gsm.bestTimes[gsm.level];
        if (!bt || gsm.elapsedTime < bt) gsm.bestTimes[gsm.level] = gsm.elapsedTime;

        // Speed run split tracking
        gsm.speedrunActive = true;
        gsm.campaignSplits[gsm.level] = gsm.elapsedTime;
        gsm.campaignTotalTime += gsm.elapsedTime;

        // Update PB splits
        const pbSplit = gsm.bestCampaignSplits[gsm.level];
        if (pbSplit === null || gsm.elapsedTime < pbSplit) {
          gsm.bestCampaignSplits[gsm.level] = gsm.elapsedTime;
          audio.playSplitGood();
        }

        // Check if we have a complete campaign run for PB total
        const completedLevels = gsm.campaignSplits.filter((_, i) => gsm.campaignSplits[i] !== undefined).length;
        if (completedLevels === LEVELS.length) {
          const totalRunTime = gsm.campaignSplits.reduce((a, b) => a + (b || 0), 0);
          if (gsm.bestCampaignTotal === null || totalRunTime < gsm.bestCampaignTotal) {
            gsm.bestCampaignTotal = totalRunTime;
            showToast('NEW CAMPAIGN PB! 🏆', 3);
          }
        }
      }
      if (gsm.mode === 'timeattack') gsm.timeAttackClears++;
      if (gsm.mode === 'daily') gsm.dailyCompleted++;
      if (gsm.mode === 'survival') {
        gsm.survivalLevelsCleared++;
        if (gsm.survivalLevelsCleared > gsm.survivalBestRun) {
          gsm.survivalBestRun = gsm.survivalLevelsCleared;
        }
      }

      // Star rating
      const stars = calcStars(gsm.elapsedTime, level.par, gsm.gemsCollected, gsm.gemsTotal);
      if (stars > (gsm.starRatings[gsm.level] || 0)) {
        gsm.starRatings[gsm.level] = stars;
      }

      // Score calculation
      const baseScore = 1000;
      const timeBonus = Math.max(0, Math.floor((level.par - gsm.elapsedTime) * 50));
      const gemBonus = gsm.gemsCollected * 200;
      const perfectBonus = isPerfect ? 500 : 0;
      const comboBonus = gsm.maxCombo >= 3 ? gsm.maxCombo * 100 : 0;
      gsm.score += baseScore + timeBonus + gemBonus + perfectBonus + comboBonus;

      addLeaderboard({
        level: level.name,
        mode: gsm.mode,
        time: gsm.elapsedTime,
        gems: gsm.gemsCollected,
        score: gsm.score,
        date: new Date().toISOString().split('T')[0],
      });

      const starDisplay = '★'.repeat(stars) + '☆'.repeat(3 - stars);
      setText('levelcomplete', 'lc-title', 'Level Complete!');
      setText('levelcomplete', 'lc-level', level.name);
      setText('levelcomplete', 'lc-time', `Time: ${gsm.elapsedTime.toFixed(1)}s`);
      setText('levelcomplete', 'lc-gems', `Gems: ${gsm.gemsCollected}/${gsm.gemsTotal}`);
      setText('levelcomplete', 'lc-par', underPar ? 'Under par!' : `Par: ${level.par}s`);
      setText('levelcomplete', 'lc-score', `Score: ${gsm.score}`);
      setText('levelcomplete', 'lc-stars', starDisplay);
      setText('levelcomplete', 'lc-combo', gsm.maxCombo >= 2 ? `Best Combo: ${gsm.maxCombo}x (+${comboBonus})` : '');

      // Speed run split display
      if (gsm.speedrunActive && gsm.mode === 'campaign') {
        const pbSplit = gsm.bestCampaignSplits[gsm.level];
        let splitText = `Split: ${gsm.elapsedTime.toFixed(1)}s`;
        if (pbSplit !== null && pbSplit < gsm.elapsedTime) {
          const delta = gsm.elapsedTime - pbSplit;
          splitText += ` (+${delta.toFixed(1)}s)`;
        } else if (pbSplit !== null) {
          splitText += ` (PB!)`;
        }
        setText('levelcomplete', 'lc-combo', gsm.maxCombo >= 2 ? `${gsm.maxCombo}x Combo (+${comboBonus}) | ${splitText}` : splitText);
      }
      if (gsm.mode === 'survival') {
        setText('levelcomplete', 'lc-par', `Survival: ${gsm.survivalLevelsCleared} levels cleared`);
      }

      audio.playGoal();
      if (particles) particles.burst(marblePos, THEMES[gsm.currentTheme].goal, 25, 0.8, 1.2);
      checkAchievements();
      gsm.save();
      break;
    }
    case 'gameover':
      setText('gameover', 'go-score', `Final Score: ${gsm.score}`);
      if (gsm.mode === 'survival') {
        setText('gameover', 'go-levels', `Survival Run: ${gsm.survivalLevelsCleared} levels | Best: ${gsm.survivalBestRun}`);
      } else {
        setText('gameover', 'go-levels', `Levels Cleared: ${gsm.totalClears}`);
      }
      audio.playGameOver();
      gsm.save();
      break;
  }
}

function startLevel(levelIdx: number) {
  loadLevel(levelIdx);
  countdownPhase = 3;
  countdownTimer = 0;
  changeState('playing');
  panels.get('countdown')!.entity.object3D.visible = true;
  setText('countdown', 'cd-text', '3');
  audio.playCountdownTick();
}

// ============================================================
// UI Event Binding (one-time setup)
// ============================================================
let uiSetup = false;
function setupUIEvents() {
  if (uiSetup) return;
  uiSetup = true;

  // Title
  const titleDoc = getDoc('title');
  titleDoc?.getElementById('btn-play')?.addEventListener('click', () => { audio.playButton(); changeState('modeselect'); });
  titleDoc?.getElementById('btn-leaderboard')?.addEventListener('click', () => { audio.playButton(); changeState('leaderboard'); });
  titleDoc?.getElementById('btn-achievements')?.addEventListener('click', () => { audio.playButton(); changeState('achievements'); });
  titleDoc?.getElementById('btn-settings')?.addEventListener('click', () => { audio.playButton(); changeState('settings'); });
  titleDoc?.getElementById('btn-help')?.addEventListener('click', () => { audio.playButton(); changeState('help'); });
  titleDoc?.getElementById('btn-stats')?.addEventListener('click', () => { audio.playButton(); changeState('stats'); });
  titleDoc?.getElementById('btn-skins')?.addEventListener('click', () => { audio.playButton(); changeState('skins'); });
  titleDoc?.getElementById('btn-speedrun')?.addEventListener('click', () => { audio.playButton(); changeState('speedrun'); });

  // Mode select
  const modeDoc = getDoc('modeselect');
  modeDoc?.getElementById('btn-campaign')?.addEventListener('click', () => { audio.playButton(); gsm.mode = 'campaign'; gsm.resetGame(); changeState('levelselect'); });
  modeDoc?.getElementById('btn-timeattack')?.addEventListener('click', () => { audio.playButton(); gsm.mode = 'timeattack'; gsm.resetGame(); changeState('levelselect'); });
  modeDoc?.getElementById('btn-zen')?.addEventListener('click', () => { audio.playButton(); gsm.mode = 'zen'; gsm.resetGame(); changeState('levelselect'); });
  modeDoc?.getElementById('btn-daily')?.addEventListener('click', () => {
    audio.playButton();
    gsm.mode = 'daily';
    gsm.resetGame();
    const seed = getDailySeed();
    const rng = seededRandom(seed);
    const dailyLevel = Math.floor(rng() * LEVELS.length);
    startLevel(dailyLevel);
  });
  modeDoc?.getElementById('btn-survival')?.addEventListener('click', () => {
    audio.playButton();
    gsm.mode = 'survival';
    gsm.resetGame();
    gsm.lives = 1; // Survival: only 1 life, no extras
    gsm.survivalLevelsCleared = 0;
    gsm.survivalIndex = 0;
    // Shuffle level order for survival
    gsm.survivalOrder = Array.from({ length: LEVELS.length }, (_, i) => i);
    for (let i = gsm.survivalOrder.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [gsm.survivalOrder[i], gsm.survivalOrder[j]] = [gsm.survivalOrder[j], gsm.survivalOrder[i]];
    }
    startLevel(gsm.survivalOrder[0]);
  });
  modeDoc?.getElementById('btn-mode-back')?.addEventListener('click', () => { audio.playButton(); changeState('title'); });

  // Level select
  const lvlDoc = getDoc('levelselect');
  for (let i = 0; i < 36; i++) {
    const idx = i;
    lvlDoc?.getElementById(`btn-lvl-${i}`)?.addEventListener('click', () => {
      audio.playButton();
      if (idx < LEVELS.length) startLevel(idx);
    });
  }
  lvlDoc?.getElementById('btn-lvl-back')?.addEventListener('click', () => { audio.playButton(); changeState('modeselect'); });

  // Pause
  const pauseDoc = getDoc('pause');
  pauseDoc?.getElementById('btn-resume')?.addEventListener('click', () => { audio.playButton(); changeState('playing'); });
  pauseDoc?.getElementById('btn-quit')?.addEventListener('click', () => { audio.playButton(); changeState('title'); });

  // Level complete
  const lcDoc = getDoc('levelcomplete');
  lcDoc?.getElementById('btn-next')?.addEventListener('click', () => {
    audio.playButton();
    if (gsm.mode === 'survival') {
      // Survival: advance to next shuffled level
      gsm.survivalIndex++;
      if (gsm.survivalIndex < gsm.survivalOrder.length) {
        startLevel(gsm.survivalOrder[gsm.survivalIndex]);
      } else {
        // Ran through all levels! Reshuffle and continue
        for (let i = gsm.survivalOrder.length - 1; i > 0; i--) {
          const j = Math.floor(Math.random() * (i + 1));
          [gsm.survivalOrder[i], gsm.survivalOrder[j]] = [gsm.survivalOrder[j], gsm.survivalOrder[i]];
        }
        gsm.survivalIndex = 0;
        startLevel(gsm.survivalOrder[0]);
      }
    } else {
      const next = gsm.level + 1;
      if (next < LEVELS.length) { startLevel(next); }
      else { changeState('title'); showToast('All levels complete!'); }
    }
  });
  lcDoc?.getElementById('btn-retry')?.addEventListener('click', () => { audio.playButton(); startLevel(gsm.level); });
  lcDoc?.getElementById('btn-lc-menu')?.addEventListener('click', () => { audio.playButton(); changeState('title'); });

  // Game over
  const goDoc = getDoc('gameover');
  goDoc?.getElementById('btn-go-retry')?.addEventListener('click', () => { audio.playButton(); gsm.resetGame(); startLevel(0); });
  goDoc?.getElementById('btn-go-menu')?.addEventListener('click', () => { audio.playButton(); changeState('title'); });

  // Leaderboard/Achievements back
  const lbDoc = getDoc('leaderboard');
  lbDoc?.getElementById('btn-lb-back')?.addEventListener('click', () => { audio.playButton(); changeState('title'); });
  const achDoc = getDoc('achievements');
  achDoc?.getElementById('btn-ach-back')?.addEventListener('click', () => { audio.playButton(); changeState('title'); });

  // Settings
  const setDoc = getDoc('settings');
  setDoc?.getElementById('btn-set-back')?.addEventListener('click', () => { audio.playButton(); changeState('title'); });
  setDoc?.getElementById('btn-vol-up')?.addEventListener('click', () => { audio.playButton(); audio.setMasterVolume(Math.min(1, audio.masterVolume + 0.1)); setText('settings', 'set-vol', `${Math.round(audio.masterVolume * 100)}%`); });
  setDoc?.getElementById('btn-vol-down')?.addEventListener('click', () => { audio.playButton(); audio.setMasterVolume(Math.max(0, audio.masterVolume - 0.1)); setText('settings', 'set-vol', `${Math.round(audio.masterVolume * 100)}%`); });
  setDoc?.getElementById('btn-sfx-up')?.addEventListener('click', () => { audio.playButton(); audio.setSfxVolume(Math.min(1, audio.sfxVolume + 0.1)); setText('settings', 'set-sfx', `${Math.round(audio.sfxVolume * 100)}%`); });
  setDoc?.getElementById('btn-sfx-down')?.addEventListener('click', () => { audio.playButton(); audio.setSfxVolume(Math.max(0, audio.sfxVolume - 0.1)); setText('settings', 'set-sfx', `${Math.round(audio.sfxVolume * 100)}%`); });
  setDoc?.getElementById('btn-music-up')?.addEventListener('click', () => { audio.playButton(); audio.setMusicVolume(Math.min(1, audio.musicVolume + 0.1)); setText('settings', 'set-music', `${Math.round(audio.musicVolume * 100)}%`); });
  setDoc?.getElementById('btn-music-down')?.addEventListener('click', () => { audio.playButton(); audio.setMusicVolume(Math.max(0, audio.musicVolume - 0.1)); setText('settings', 'set-music', `${Math.round(audio.musicVolume * 100)}%`); });
  setDoc?.getElementById('btn-theme-next')?.addEventListener('click', () => {
    audio.playButton();
    gsm.currentTheme = (gsm.currentTheme + 1) % THEMES.length;
    gsm.themesUsed.add(gsm.currentTheme);
    setText('settings', 'set-theme', THEMES[gsm.currentTheme].name);
    gsm.save();
  });
  setDoc?.getElementById('btn-theme-prev')?.addEventListener('click', () => {
    audio.playButton();
    gsm.currentTheme = (gsm.currentTheme - 1 + THEMES.length) % THEMES.length;
    gsm.themesUsed.add(gsm.currentTheme);
    setText('settings', 'set-theme', THEMES[gsm.currentTheme].name);
    gsm.save();
  });

  // Help back
  const helpDoc = getDoc('help');
  helpDoc?.getElementById('btn-help-back')?.addEventListener('click', () => { audio.playButton(); changeState('title'); });

  // Stats back
  const statsDoc = getDoc('stats');
  statsDoc?.getElementById('btn-stats-back')?.addEventListener('click', () => { audio.playButton(); changeState('title'); });

  // Skins
  const skinsDoc = getDoc('skins');
  skinsDoc?.getElementById('btn-skins-back')?.addEventListener('click', () => { audio.playButton(); changeState('title'); });
  for (let i = 0; i < MARBLE_SKINS.length; i++) {
    const idx = i;
    skinsDoc?.getElementById(`btn-skin-${i}`)?.addEventListener('click', () => {
      audio.playButton();
      gsm.currentSkin = idx;
      gsm.skinsUsed.add(idx);
      updateSkinsPanel();
      gsm.save();
      showToast(`Equipped: ${MARBLE_SKINS[idx].name}`, 1.5);
      checkAchievements();
    });
  }

  // Speedrun panel back
  const srDoc = getDoc('speedrun');
  srDoc?.getElementById('btn-sr-back')?.addEventListener('click', () => { audio.playButton(); changeState('title'); });
}

// ============================================================
// Main Game Loop
// ============================================================

let gravitySwitchCooldown = 0;

function update() {
  const now = performance.now();
  const dt = Math.min((now - lastTime) / 1000, 0.05); // cap at 50ms
  lastTime = now;
  const time = now / 1000;

  // Try to wire UI events (docs may not be ready on first frame)
  setupUIEvents();

  // Toast timer
  if (toastTimer > 0) {
    toastTimer -= dt;
    if (toastTimer <= 0) {
      const tp = panels.get('toast');
      if (tp) tp.entity.object3D.visible = false;
    }
  }

  // Countdown
  if (countdownPhase > 0 && gsm.state === 'playing') {
    countdownTimer += dt;
    if (countdownTimer >= 1) {
      countdownTimer = 0;
      countdownPhase--;
      if (countdownPhase > 0) {
        setText('countdown', 'cd-text', `${countdownPhase}`);
        audio.playCountdownTick();
      } else {
        setText('countdown', 'cd-text', 'GO!');
        audio.playGameStart();
        gsm.startTime = performance.now();
        setTimeout(() => {
          const cdP = panels.get('countdown');
          if (cdP) cdP.entity.object3D.visible = false;
        }, 500);
      }
    }
    // Don't run physics during countdown
    requestAnimationFrame(update);
    return;
  }

  // Animate environment
  ambientParticles?.update(time);
  animateDecorations(decos, time);
  particles?.update(dt);

  if (gsm.state === 'playing' && board && marbleMesh && marbleGlow) {
    // Update elapsed time
    gsm.elapsedTime = (performance.now() - gsm.startTime) / 1000;
    updateHUD();

    // ---- Input: board tilt ----
    targetTilt.set(0, 0);

    // Keyboard
    if (keys['a'] || keys['arrowleft']) targetTilt.x = -MAX_TILT;
    if (keys['d'] || keys['arrowright']) targetTilt.x = MAX_TILT;
    if (keys['w'] || keys['arrowup']) targetTilt.y = -MAX_TILT;
    if (keys['s'] || keys['arrowdown']) targetTilt.y = MAX_TILT;

    // XR thumbstick input
    const xrInput = (world.input as any)?.xr;
    if (xrInput) {
      const leftThumb = xrInput.left?.axes;
      if (leftThumb && leftThumb.length >= 4) {
        targetTilt.x = leftThumb[2] * MAX_TILT;
        targetTilt.y = leftThumb[3] * MAX_TILT;
      }
    }

    // Pause input
    if (keys['escape']) { keys['escape'] = false; changeState('paused'); }

    // Smooth tilt
    boardTilt.x += (targetTilt.x - boardTilt.x) * Math.min(TILT_SPEED * dt * 10, 1);
    boardTilt.y += (targetTilt.y - boardTilt.y) * Math.min(TILT_SPEED * dt * 10, 1);

    // Apply tilt to board group
    boardEntity!.rotation.x = boardTilt.y;
    boardEntity!.rotation.z = -boardTilt.x;

    // ---- Gravity ----
    // Gravity component on tilted surface (flipped if gravity switch active)
    const gravMul = gsm.gravityFlipped ? -1 : 1;
    const gx = Math.sin(boardTilt.x) * GRAVITY * gravMul;
    const gz = Math.sin(boardTilt.y) * GRAVITY * gravMul;

    // Check current tile
    const tileType = getTileAt(marblePos.x, marblePos.z, board.gridW, board.gridH, board.grid);
    onIce = tileType === TILE.ICE;
    const friction = onIce ? ICE_FRICTION : FRICTION;

    // Apply gravity acceleration
    marbleVel.x += gx * dt;
    marbleVel.y += gz * dt;

    // Apply friction
    marbleVel.x *= friction;
    marbleVel.y *= friction;

    // Boost pads
    if (tileType === TILE.BOOST) {
      marbleVel.y += BOOST_IMPULSE * dt * 10;
      gsm.boostsHit++;
      if (Math.random() < 0.1) audio.playBoost();
    }

    // Clamp speed
    const speedMult = gsm.slowmoActive ? 0.5 : 1.0;
    const speed = Math.sqrt(marbleVel.x * marbleVel.x + marbleVel.y * marbleVel.y);
    const effectiveMaxSpeed = MARBLE_MAX_SPEED * speedMult;
    if (speed > effectiveMaxSpeed) {
      marbleVel.x *= effectiveMaxSpeed / speed;
      marbleVel.y *= effectiveMaxSpeed / speed;
    }

    // Move marble
    marblePos.x += marbleVel.x * dt;
    marblePos.z += marbleVel.y * dt;

    // Wall collisions
    const push = checkWallCollision(marblePos.x, marblePos.z, board.grid, board.gridW, board.gridH);
    if (push) {
      marblePos.x += push.x;
      marblePos.z += push.y;
      // Reflect velocity
      if (Math.abs(push.x) > Math.abs(push.y)) {
        marbleVel.x = -marbleVel.x * BOUNCE_DAMP;
      } else {
        marbleVel.y = -marbleVel.y * BOUNCE_DAMP;
      }
      audio.playBounce(speed);
      if (particles) particles.burst(
        new THREE.Vector3(marblePos.x, marblePos.y, marblePos.z),
        THEMES[gsm.currentTheme].accent, 5, 0.3, 0.4
      );
    }

    // Rolling sound
    rollSoundTimer -= dt;
    if (speed > 0.2 && rollSoundTimer <= 0) {
      audio.playRoll(speed);
      rollSoundTimer = 0.08;
    }
    if (onIce && speed > 0.3 && Math.random() < 0.05) audio.playIceSlide();

    // Update marble mesh position
    marbleMesh.position.copy(marblePos);
    marbleGlow.position.copy(marblePos);
    if (shieldMesh) {
      shieldMesh.position.copy(marblePos);
      // Shield visual
      if (gsm.shieldActive) {
        (shieldMesh.material as THREE.MeshBasicMaterial).opacity = 0.25 + Math.sin(time * 6) * 0.1;
        shieldMesh.rotation.y = time * 3;
      } else {
        (shieldMesh.material as THREE.MeshBasicMaterial).opacity = 0;
      }
    }

    // Marble rotation based on velocity
    marbleMesh.rotation.z -= marbleVel.x * dt * 15;
    marbleMesh.rotation.x += marbleVel.y * dt * 15;

    // Trail
    if (trail && speed > 0.1) {
      trail.addPoint(marblePos.clone());
    }
    // Update trail particles
    if (trail) trail.updateParticles(dt, marblePos, speed);

    // Teleporter cooldown
    if (teleCooldown > 0) teleCooldown -= dt;

    // Power-up timers
    if (gsm.shieldActive) {
      gsm.shieldTimer -= dt;
      if (gsm.shieldTimer <= 0) { gsm.shieldActive = false; gsm.shieldTimer = 0; }
    }
    if (gsm.magnetActive) {
      gsm.magnetTimer -= dt;
      if (gsm.magnetTimer <= 0) { gsm.magnetActive = false; gsm.magnetTimer = 0; }
    }
    if (gsm.slowmoActive) {
      gsm.slowmoTimer -= dt;
      if (gsm.slowmoTimer <= 0) { gsm.slowmoActive = false; gsm.slowmoTimer = 0; }
    }

    // Combo timer
    if (gsm.comboTimer > 0) {
      gsm.comboTimer -= dt;
      if (gsm.comboTimer <= 0) {
        gsm.comboCount = 0;
        gsm.comboTimer = 0;
      }
    }

    // Magnet effect: attract nearby gems
    if (gsm.magnetActive && board) {
      const bw = board.gridW * BOARD_CELL;
      const bh = board.gridH * BOARD_CELL;
      for (const gem of board.gems) {
        if (!gem.visible) continue;
        const dx = gem.position.x - marblePos.x;
        const dz = gem.position.z - marblePos.z;
        const dist = Math.sqrt(dx * dx + dz * dz);
        if (dist < BOARD_CELL * 2.5 && dist > 0.01) {
          // Move gem toward marble
          const pull = Math.min(BOARD_CELL * 3 * dt / dist, 0.8);
          gem.position.x -= dx * pull;
          gem.position.z -= dz * pull;
          // Check if gem is close enough to collect
          if (dist < MARBLE_RADIUS * 2) {
            const col = Math.floor((gem.userData?.origX ?? gem.position.x + bw / 2) / BOARD_CELL);
            const row = Math.floor((gem.userData?.origZ ?? gem.position.z + bh / 2) / BOARD_CELL);
            gem.visible = false;
            gsm.gemsCollected++;
            gsm.totalGems++;
            // Combo system
            gsm.comboCount++;
            gsm.comboTimer = COMBO_WINDOW;
            if (gsm.comboCount > gsm.maxCombo) gsm.maxCombo = gsm.comboCount;
            const comboMult = Math.min(gsm.comboCount, 5);
            const gemScore = 200 * comboMult;
            gsm.score += gemScore;
            magnetGems++;
            audio.playGemCollect();
            if (gsm.comboCount >= 2) audio.playCombo(gsm.comboCount);
            magnetPullTimer -= dt;
            if (magnetPullTimer <= 0) { audio.playMagnetPull(); magnetPullTimer = 0.3; }
            if (particles) particles.burst(gem.position.clone(), THEMES[gsm.currentTheme].gem, 8, 0.4, 0.5);
            showToast(gsm.comboCount >= 2 ? `${gsm.comboCount}x Combo! +${gemScore}` : `Magnet Gem! +200`, 0.8);
          }
        }
      }
    }

    // ---- Tile interactions ----
    const currentTile = getTileAt(marblePos.x, marblePos.z, board.gridW, board.gridH, board.grid);

    // Hole: fall!
    if (currentTile === TILE.HOLE) {
      if (gsm.shieldActive) {
        // Shield absorbs the fall
        gsm.shieldActive = false;
        gsm.shieldTimer = 0;
        gsm.shieldsUsed++;
        audio.playShieldBreak();
        if (particles) particles.burst(marblePos.clone(), 0x4488ff, 20, 0.8, 1.0);
        showToast('Shield absorbed fall!', 2);
        resetMarble();
        checkAchievements();
      } else {
        gsm.lives--;
        gsm.totalDeaths++;
        gsm.noDeathStreak = 0;
        audio.playFall();
        if (particles) particles.burst(marblePos.clone(), 0xff3333, 15, 0.6, 0.8);
        if (gsm.lives <= 0) {
          changeState('gameover');
        } else {
          showToast(`Fell! Lives: ${gsm.lives}`, 1.5);
          resetMarble();
        }
      }
    }

    // Gem: collect
    if (currentTile === TILE.GEM) {
      // Find and hide the gem mesh at this position
      const bw = board.gridW * BOARD_CELL;
      const bh = board.gridH * BOARD_CELL;
      const col = Math.floor((marblePos.x + bw / 2) / BOARD_CELL);
      const row = Math.floor((marblePos.z + bh / 2) / BOARD_CELL);
      // Mark tile as empty
      board.grid[row][col] = TILE.EMPTY;
      // Hide gem mesh
      for (const gem of board.gems) {
        const gx = gem.position.x;
        const gz = gem.position.z;
        const gcol = Math.floor((gx + bw / 2) / BOARD_CELL);
        const grow = Math.floor((gz + bh / 2) / BOARD_CELL);
        if (gcol === col && grow === row && gem.visible) {
          gem.visible = false;
          gsm.gemsCollected++;
          gsm.totalGems++;
          // Combo system
          gsm.comboCount++;
          gsm.comboTimer = COMBO_WINDOW;
          if (gsm.comboCount > gsm.maxCombo) gsm.maxCombo = gsm.comboCount;
          const comboMult = Math.min(gsm.comboCount, 5);
          const gemScore = 200 * comboMult;
          gsm.score += gemScore;
          if (gsm.magnetActive) magnetGems++;
          audio.playGemCollect();
          if (gsm.comboCount >= 2) audio.playCombo(gsm.comboCount);
          if (particles) particles.burst(gem.position.clone(), THEMES[gsm.currentTheme].gem, 12, 0.5, 0.6);
          showToast(gsm.comboCount >= 2 ? `${gsm.comboCount}x Combo! +${gemScore}` : `Gem! +200`, 1);
          break;
        }
      }
    }

    // Goal: level complete!
    if (currentTile === TILE.GOAL) {
      changeState('levelcomplete');
    }

    // Teleporter
    if ((currentTile === TILE.TELE_A || currentTile === TILE.TELE_B) && teleCooldown <= 0) {
      const target = currentTile === TILE.TELE_A ? board.teleB : board.teleA;
      if (target) {
        const destLocal = gridToLocal(target.x, target.y, board.gridW, board.gridH);
        marblePos.copy(destLocal);
        teleCooldown = 0.5;
        gsm.warpsUsed++;
        audio.playTeleport();
        if (particles) particles.burst(marblePos.clone(), 0xff00ff, 15, 0.6, 0.8);
        showToast('Warped!', 1);
      }
    }

    // Power-up pickup
    if (board.powerups) {
      const bw = board.gridW * BOARD_CELL;
      const bh = board.gridH * BOARD_CELL;
      for (const pu of board.powerups) {
        if (pu.collected) continue;
        const dx = pu.mesh.position.x - marblePos.x;
        const dz = pu.mesh.position.z - marblePos.z;
        const dist = Math.sqrt(dx * dx + dz * dz);
        if (dist < BOARD_CELL * 0.5) {
          pu.collected = true;
          pu.mesh.visible = false;
          pu.glowMesh.visible = false;
          board.grid[pu.row][pu.col] = TILE.EMPTY;
          gsm.powerupsCollected++;
          if (pu.type === TILE.POWERUP_SHIELD) {
            gsm.shieldActive = true;
            gsm.shieldTimer = 15;
            audio.playPowerup('shield');
            showToast('Shield Active! (15s)', 2);
            if (particles) particles.burst(marblePos.clone(), 0x4488ff, 15, 0.6, 0.8);
          } else if (pu.type === TILE.POWERUP_MAGNET) {
            gsm.magnetActive = true;
            gsm.magnetTimer = 10;
            magnetGems = 0;
            audio.playPowerup('magnet');
            showToast('Magnet Active! (10s)', 2);
            if (particles) particles.burst(marblePos.clone(), 0xffcc00, 15, 0.6, 0.8);
          } else if (pu.type === TILE.POWERUP_SLOWMO) {
            gsm.slowmoActive = true;
            gsm.slowmoTimer = 8;
            audio.playPowerup('slowmo');
            showToast('Slow-Mo Active! (8s)', 2);
            if (particles) particles.burst(marblePos.clone(), 0xcc44ff, 15, 0.6, 0.8);
          }
          checkAchievements();
        }
      }
    }

    // Gravity switch detection
    if (gravitySwitchCooldown > 0) gravitySwitchCooldown -= dt;
    if (board.gravitySwitches && gravitySwitchCooldown <= 0) {
      for (const gs of board.gravitySwitches) {
        const bw = board.gridW * BOARD_CELL;
        const bh = board.gridH * BOARD_CELL;
        const gx = gs.col * BOARD_CELL - bw / 2 + BOARD_CELL / 2;
        const gz = gs.row * BOARD_CELL - bh / 2 + BOARD_CELL / 2;
        const dx = gx - marblePos.x;
        const dz = gz - marblePos.z;
        const dist = Math.sqrt(dx * dx + dz * dz);
        if (dist < BOARD_CELL * 0.4) {
          gsm.gravityFlipped = !gsm.gravityFlipped;
          gravitySwitchCooldown = 0.8;
          audio.playTeleport(); // reuse teleport sound
          showToast(gsm.gravityFlipped ? 'Gravity Reversed!' : 'Gravity Normal!', 1.5);
          if (particles) {
            particles.burst(
              new THREE.Vector3(marblePos.x, marblePos.y, marblePos.z),
              0x00ff00, 12, 0.5, 0.6
            );
          }
        }
      }
    }

    // Moving wall collision check
    if (board.movingWalls) {
      for (const mw of board.movingWalls) {
        const wPos = mw.mesh.position;
        const hw = BOARD_CELL * 0.475;
        // Closest point on moving wall box to marble center
        const cx = Math.max(wPos.x - hw, Math.min(marblePos.x, wPos.x + hw));
        const cz = Math.max(wPos.z - hw, Math.min(marblePos.z, wPos.z + hw));
        const dx = marblePos.x - cx;
        const dz = marblePos.z - cz;
        const dist = Math.sqrt(dx * dx + dz * dz);
        if (dist < MARBLE_RADIUS && dist > 0.0001) {
          const overlap = MARBLE_RADIUS - dist;
          marblePos.x += (dx / dist) * overlap;
          marblePos.z += (dz / dist) * overlap;
          if (Math.abs(dx) > Math.abs(dz)) {
            marbleVel.x = -marbleVel.x * BOUNCE_DAMP;
          } else {
            marbleVel.y = -marbleVel.y * BOUNCE_DAMP;
          }
          const spd = Math.sqrt(marbleVel.x * marbleVel.x + marbleVel.y * marbleVel.y);
          audio.playBounce(spd);
          if (particles) {
            particles.burst(
              new THREE.Vector3(marblePos.x, marblePos.y, marblePos.z),
              0xff8800, 5, 0.3, 0.4
            );
          }
        }
      }
    }

    // Bumper collision check
    if (board.bumpers) {
      for (const b of board.bumpers) {
        const bx = b.mesh.position.x;
        const bz = b.mesh.position.z;
        const dx = marblePos.x - bx;
        const dz = marblePos.z - bz;
        const dist = Math.sqrt(dx * dx + dz * dz);
        const bumperRadius = BOARD_CELL * 0.3;
        if (dist < bumperRadius + MARBLE_RADIUS && dist > 0.0001) {
          // Push marble out and launch with boosted velocity
          const overlap = (bumperRadius + MARBLE_RADIUS) - dist;
          const nx = dx / dist;
          const nz = dz / dist;
          marblePos.x += nx * overlap;
          marblePos.z += nz * overlap;
          // Launch velocity — 1.5x current speed in bounce direction, minimum impulse
          const spd = Math.sqrt(marbleVel.x * marbleVel.x + marbleVel.y * marbleVel.y);
          const launchSpeed = Math.max(spd * 1.5, 1.2);
          marbleVel.x = nx * launchSpeed;
          marbleVel.y = nz * launchSpeed;
          gsm.bumpersHit++;
          audio.playBumper();
          if (particles) {
            particles.burst(
              new THREE.Vector3(marblePos.x, marblePos.y, marblePos.z),
              0xff66ff, 15, 0.7, 0.6
            );
          }
          showToast('Bumper!', 0.6);
          // Visual feedback — scale bump
          b.mesh.scale.set(1.4, 1.4, 1.4);
          setTimeout(() => { b.mesh.scale.set(1, 1, 1); }, 150);
          checkAchievements();
        }
      }
    }

    // Animate board elements
    animateBoard(board, time);
  }

  // Pause: listen for escape
  if (gsm.state === 'paused') {
    if (keys['escape']) { keys['escape'] = false; changeState('playing'); }
  }

  requestAnimationFrame(update);
}

// ============================================================
// Start
// ============================================================
gsm.themesUsed.add(gsm.currentTheme);
changeState('title');
requestAnimationFrame(update);

// board.ts — Board geometry, maze rendering, tile objects
import * as THREE from 'three';
import {
  LevelDef, TILE, TileType, BoardTheme, THEMES,
  BOARD_CELL, WALL_HEIGHT, BOARD_THICKNESS, MARBLE_RADIUS
} from './types.js';

export interface BoardObjects {
  group: THREE.Group;
  floor: THREE.Mesh;
  walls: THREE.Mesh[];
  holes: THREE.Mesh[];
  gems: THREE.Mesh[];
  goalMesh: THREE.Mesh | null;
  startPos: THREE.Vector2;
  goalPos: THREE.Vector2;
  teleA: THREE.Vector2 | null;
  teleB: THREE.Vector2 | null;
  teleMeshA: THREE.Mesh | null;
  teleMeshB: THREE.Mesh | null;
  iceTiles: THREE.Mesh[];
  boostTiles: { mesh: THREE.Mesh; dir: THREE.Vector2 }[];
  powerups: { mesh: THREE.Mesh; glowMesh: THREE.Mesh; type: number; col: number; row: number; collected: boolean }[];
  movingWalls: { mesh: THREE.Mesh; edgeMesh: THREE.LineSegments; col: number; row: number; axis: 'x' | 'z'; speed: number; range: number; basePos: THREE.Vector3 }[];
  gravitySwitches: { mesh: THREE.Mesh; glowMesh: THREE.Mesh; col: number; row: number; cooldown: number }[];
  bumpers: { mesh: THREE.Mesh; glowMesh: THREE.Mesh; col: number; row: number }[];
  gridW: number;
  gridH: number;
  grid: number[][];
}

const _v2 = new THREE.Vector2();

export function buildBoard(level: LevelDef, themeIdx: number): BoardObjects {
  const theme = THEMES[themeIdx] || THEMES[0];
  const grid = level.grid;
  const gridH = grid.length;
  const gridW = grid[0].length;
  const bw = gridW * BOARD_CELL;
  const bh = gridH * BOARD_CELL;

  const group = new THREE.Group();

  // Board floor
  const floorGeo = new THREE.BoxGeometry(bw, BOARD_THICKNESS, bh);
  const floorMat = new THREE.MeshStandardMaterial({
    color: theme.floor,
    roughness: 0.6,
    metalness: 0.3,
  });
  const floor = new THREE.Mesh(floorGeo, floorMat);
  floor.position.set(0, -BOARD_THICKNESS / 2, 0);
  group.add(floor);

  // Neon grid lines on the floor
  const gridLineMat = new THREE.LineBasicMaterial({ color: theme.accent, transparent: true, opacity: 0.15 });
  for (let r = 0; r <= gridH; r++) {
    const z = r * BOARD_CELL - bh / 2;
    const pts = [new THREE.Vector3(-bw / 2, 0.001, z), new THREE.Vector3(bw / 2, 0.001, z)];
    group.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(pts), gridLineMat));
  }
  for (let c = 0; c <= gridW; c++) {
    const x = c * BOARD_CELL - bw / 2;
    const pts = [new THREE.Vector3(x, 0.001, -bh / 2), new THREE.Vector3(x, 0.001, bh / 2)];
    group.add(new THREE.Line(new THREE.BufferGeometry().setFromPoints(pts), gridLineMat));
  }

  // Edge glow
  const edgeGeo = new THREE.EdgesGeometry(floorGeo);
  const edgeMat = new THREE.LineBasicMaterial({ color: theme.accent, transparent: true, opacity: 0.5 });
  const edgeLines = new THREE.LineSegments(edgeGeo, edgeMat);
  edgeLines.position.copy(floor.position);
  group.add(edgeLines);

  const walls: THREE.Mesh[] = [];
  const holes: THREE.Mesh[] = [];
  const gems: THREE.Mesh[] = [];
  const iceTiles: THREE.Mesh[] = [];
  const boostTiles: { mesh: THREE.Mesh; dir: THREE.Vector2 }[] = [];
  let goalMesh: THREE.Mesh | null = null;
  let startPos = new THREE.Vector2(1, 1);
  let goalPos = new THREE.Vector2(6, 6);
  let teleA: THREE.Vector2 | null = null;
  let teleB: THREE.Vector2 | null = null;
  let teleMeshA: THREE.Mesh | null = null;
  let teleMeshB: THREE.Mesh | null = null;

  const wallGeo = new THREE.BoxGeometry(BOARD_CELL * 0.95, WALL_HEIGHT, BOARD_CELL * 0.95);
  const wallMat = new THREE.MeshStandardMaterial({
    color: theme.wall,
    emissive: new THREE.Color(theme.wall),
    emissiveIntensity: 0.3,
    roughness: 0.4,
    metalness: 0.5,
  });

  const holeGeo = new THREE.CylinderGeometry(BOARD_CELL * 0.35, BOARD_CELL * 0.35, BOARD_THICKNESS + 0.01, 16);
  const holeMat = new THREE.MeshStandardMaterial({ color: 0x220000, emissive: 0xff0000, emissiveIntensity: 0.2 });

  const gemGeo = new THREE.OctahedronGeometry(BOARD_CELL * 0.15);
  const gemMat = new THREE.MeshStandardMaterial({
    color: theme.gem,
    emissive: new THREE.Color(theme.gem),
    emissiveIntensity: 0.6,
    roughness: 0.2,
    metalness: 0.8,
  });

  const goalGeo = new THREE.TorusGeometry(BOARD_CELL * 0.3, BOARD_CELL * 0.06, 8, 16);
  const goalMat = new THREE.MeshStandardMaterial({
    color: theme.goal,
    emissive: new THREE.Color(theme.goal),
    emissiveIntensity: 0.8,
    roughness: 0.3,
  });

  const teleGeo = new THREE.TorusGeometry(BOARD_CELL * 0.28, BOARD_CELL * 0.05, 8, 16);
  const teleMatA = new THREE.MeshStandardMaterial({ color: 0xff00ff, emissive: 0xff00ff, emissiveIntensity: 0.6 });
  const teleMatB = new THREE.MeshStandardMaterial({ color: 0x8800ff, emissive: 0x8800ff, emissiveIntensity: 0.6 });

  const iceGeo = new THREE.PlaneGeometry(BOARD_CELL * 0.9, BOARD_CELL * 0.9);
  const iceMat = new THREE.MeshStandardMaterial({
    color: 0x88ccff,
    emissive: 0x4488cc,
    emissiveIntensity: 0.3,
    transparent: true,
    opacity: 0.5,
    roughness: 0.1,
    metalness: 0.9,
  });

  const boostGeo = new THREE.PlaneGeometry(BOARD_CELL * 0.8, BOARD_CELL * 0.8);
  const boostMat = new THREE.MeshStandardMaterial({
    color: 0x00ff88,
    emissive: 0x00ff88,
    emissiveIntensity: 0.5,
    transparent: true,
    opacity: 0.6,
  });

  // Power-up geometries
  const puShieldGeo = new THREE.SphereGeometry(BOARD_CELL * 0.22, 12, 12);
  const puShieldMat = new THREE.MeshStandardMaterial({
    color: 0x4488ff, emissive: 0x2266ff, emissiveIntensity: 0.7,
    transparent: true, opacity: 0.7, roughness: 0.1, metalness: 0.9,
  });
  const puMagnetGeo = new THREE.CylinderGeometry(BOARD_CELL * 0.15, BOARD_CELL * 0.2, BOARD_CELL * 0.2, 6);
  const puMagnetMat = new THREE.MeshStandardMaterial({
    color: 0xffcc00, emissive: 0xffaa00, emissiveIntensity: 0.7,
    roughness: 0.3, metalness: 0.8,
  });
  const puSlowmoGeo = new THREE.TorusKnotGeometry(BOARD_CELL * 0.12, BOARD_CELL * 0.04, 32, 8, 2, 3);
  const puSlowmoMat = new THREE.MeshStandardMaterial({
    color: 0xcc44ff, emissive: 0xaa22ff, emissiveIntensity: 0.7,
    roughness: 0.2, metalness: 0.7,
  });
  const puGlowGeo = new THREE.SphereGeometry(BOARD_CELL * 0.3, 8, 8);

  // Moving wall and gravity switch materials
  const movWallMat = new THREE.MeshStandardMaterial({
    color: 0xff8800, emissive: 0xff4400, emissiveIntensity: 0.5,
    roughness: 0.3, metalness: 0.6,
  });
  const gravSwitchGeo = new THREE.CylinderGeometry(BOARD_CELL * 0.25, BOARD_CELL * 0.25, 0.01, 8);
  const gravSwitchMat = new THREE.MeshStandardMaterial({
    color: 0x00ff00, emissive: 0x00ff00, emissiveIntensity: 0.6,
    roughness: 0.2, metalness: 0.8,
  });
  const gravGlowGeo = new THREE.SphereGeometry(BOARD_CELL * 0.35, 8, 8);

  // Bumper geometry
  const bumperGeo = new THREE.SphereGeometry(BOARD_CELL * 0.3, 12, 12);
  const bumperMat = new THREE.MeshStandardMaterial({
    color: 0xff66ff, emissive: 0xff22cc, emissiveIntensity: 0.7,
    roughness: 0.2, metalness: 0.6,
  });
  const bumperGlowGeo = new THREE.SphereGeometry(BOARD_CELL * 0.45, 8, 8);

  const powerups: { mesh: THREE.Mesh; glowMesh: THREE.Mesh; type: number; col: number; row: number; collected: boolean }[] = [];
  const movingWalls: { mesh: THREE.Mesh; edgeMesh: THREE.LineSegments; col: number; row: number; axis: 'x' | 'z'; speed: number; range: number; basePos: THREE.Vector3 }[] = [];
  const gravitySwitches: { mesh: THREE.Mesh; glowMesh: THREE.Mesh; col: number; row: number; cooldown: number }[] = [];
  const bumpers: { mesh: THREE.Mesh; glowMesh: THREE.Mesh; col: number; row: number }[] = [];

  for (let r = 0; r < gridH; r++) {
    for (let c = 0; c < gridW; c++) {
      const tile = grid[r][c] as TileType;
      const x = c * BOARD_CELL - bw / 2 + BOARD_CELL / 2;
      const z = r * BOARD_CELL - bh / 2 + BOARD_CELL / 2;

      switch (tile) {
        case TILE.WALL: {
          const w = new THREE.Mesh(wallGeo, wallMat);
          w.position.set(x, WALL_HEIGHT / 2, z);
          group.add(w);
          // Wireframe edge
          const we = new THREE.LineSegments(
            new THREE.EdgesGeometry(wallGeo),
            new THREE.LineBasicMaterial({ color: theme.accent, transparent: true, opacity: 0.6 })
          );
          we.position.copy(w.position);
          group.add(we);
          walls.push(w);
          break;
        }
        case TILE.HOLE: {
          const h = new THREE.Mesh(holeGeo, holeMat);
          h.position.set(x, -BOARD_THICKNESS / 2, z);
          h.rotation.x = 0;
          group.add(h);
          // Glow ring around hole
          const ring = new THREE.Mesh(
            new THREE.TorusGeometry(BOARD_CELL * 0.36, 0.003, 8, 24),
            new THREE.MeshBasicMaterial({ color: 0xff3333, transparent: true, opacity: 0.7 })
          );
          ring.position.set(x, 0.002, z);
          ring.rotation.x = -Math.PI / 2;
          group.add(ring);
          holes.push(h);
          break;
        }
        case TILE.GEM: {
          const g = new THREE.Mesh(gemGeo, gemMat.clone());
          g.position.set(x, BOARD_CELL * 0.2, z);
          group.add(g);
          // Glow sphere
          const glow = new THREE.Mesh(
            new THREE.SphereGeometry(BOARD_CELL * 0.2, 8, 8),
            new THREE.MeshBasicMaterial({ color: theme.gem, transparent: true, opacity: 0.15 })
          );
          glow.position.copy(g.position);
          group.add(glow);
          gems.push(g);
          break;
        }
        case TILE.GOAL: {
          goalMesh = new THREE.Mesh(goalGeo, goalMat);
          goalMesh.position.set(x, BOARD_CELL * 0.15, z);
          goalMesh.rotation.x = -Math.PI / 2;
          group.add(goalMesh);
          goalPos.set(c, r);
          // Beacon
          const beacon = new THREE.Mesh(
            new THREE.CylinderGeometry(0.003, 0.003, WALL_HEIGHT * 2, 8),
            new THREE.MeshBasicMaterial({ color: theme.goal, transparent: true, opacity: 0.4 })
          );
          beacon.position.set(x, WALL_HEIGHT, z);
          group.add(beacon);
          break;
        }
        case TILE.START: {
          startPos.set(c, r);
          // Start marker ring
          const sRing = new THREE.Mesh(
            new THREE.TorusGeometry(BOARD_CELL * 0.25, 0.003, 8, 24),
            new THREE.MeshBasicMaterial({ color: 0x00ffff, transparent: true, opacity: 0.5 })
          );
          sRing.position.set(x, 0.002, z);
          sRing.rotation.x = -Math.PI / 2;
          group.add(sRing);
          break;
        }
        case TILE.TELE_A: {
          teleA = new THREE.Vector2(c, r);
          teleMeshA = new THREE.Mesh(teleGeo, teleMatA);
          teleMeshA.position.set(x, BOARD_CELL * 0.12, z);
          teleMeshA.rotation.x = -Math.PI / 2;
          group.add(teleMeshA);
          break;
        }
        case TILE.TELE_B: {
          teleB = new THREE.Vector2(c, r);
          teleMeshB = new THREE.Mesh(teleGeo, teleMatB);
          teleMeshB.position.set(x, BOARD_CELL * 0.12, z);
          teleMeshB.rotation.x = -Math.PI / 2;
          group.add(teleMeshB);
          break;
        }
        case TILE.ICE: {
          const ice = new THREE.Mesh(iceGeo, iceMat.clone());
          ice.position.set(x, 0.002, z);
          ice.rotation.x = -Math.PI / 2;
          group.add(ice);
          iceTiles.push(ice);
          break;
        }
        case TILE.BOOST: {
          const bm = new THREE.Mesh(boostGeo, boostMat.clone());
          bm.position.set(x, 0.003, z);
          bm.rotation.x = -Math.PI / 2;
          group.add(bm);
          // Chevron arrows on boost pad
          const arrow = new THREE.Mesh(
            new THREE.ConeGeometry(BOARD_CELL * 0.12, BOARD_CELL * 0.2, 4),
            new THREE.MeshBasicMaterial({ color: 0x00ff88, transparent: true, opacity: 0.6 })
          );
          arrow.position.set(x, 0.01, z);
          arrow.rotation.x = -Math.PI / 2;
          group.add(arrow);
          boostTiles.push({ mesh: bm, dir: new THREE.Vector2(0, 1) }); // default forward boost
          break;
        }
        case TILE.POWERUP_SHIELD: {
          const pm = new THREE.Mesh(puShieldGeo, puShieldMat.clone());
          pm.position.set(x, BOARD_CELL * 0.25, z);
          group.add(pm);
          const pg = new THREE.Mesh(puGlowGeo, new THREE.MeshBasicMaterial({ color: 0x4488ff, transparent: true, opacity: 0.15 }));
          pg.position.copy(pm.position);
          group.add(pg);
          powerups.push({ mesh: pm, glowMesh: pg, type: TILE.POWERUP_SHIELD, col: c, row: r, collected: false });
          break;
        }
        case TILE.POWERUP_MAGNET: {
          const pm = new THREE.Mesh(puMagnetGeo, puMagnetMat.clone());
          pm.position.set(x, BOARD_CELL * 0.2, z);
          group.add(pm);
          const pg = new THREE.Mesh(puGlowGeo, new THREE.MeshBasicMaterial({ color: 0xffcc00, transparent: true, opacity: 0.15 }));
          pg.position.copy(pm.position);
          group.add(pg);
          powerups.push({ mesh: pm, glowMesh: pg, type: TILE.POWERUP_MAGNET, col: c, row: r, collected: false });
          break;
        }
        case TILE.POWERUP_SLOWMO: {
          const pm = new THREE.Mesh(puSlowmoGeo, puSlowmoMat.clone());
          pm.position.set(x, BOARD_CELL * 0.2, z);
          group.add(pm);
          const pg = new THREE.Mesh(puGlowGeo, new THREE.MeshBasicMaterial({ color: 0xcc44ff, transparent: true, opacity: 0.15 }));
          pg.position.copy(pm.position);
          group.add(pg);
          powerups.push({ mesh: pm, glowMesh: pg, type: TILE.POWERUP_SLOWMO, col: c, row: r, collected: false });
          break;
        }
        case TILE.MOVING_WALL: {
          const mw = new THREE.Mesh(wallGeo, movWallMat.clone());
          mw.position.set(x, WALL_HEIGHT / 2, z);
          group.add(mw);
          const mwe = new THREE.LineSegments(
            new THREE.EdgesGeometry(wallGeo),
            new THREE.LineBasicMaterial({ color: 0xff8800, transparent: true, opacity: 0.7 })
          );
          mwe.position.copy(mw.position);
          group.add(mwe);
          // Alternate axis based on position for variety
          const axis = (c + r) % 2 === 0 ? 'x' : 'z';
          movingWalls.push({
            mesh: mw, edgeMesh: mwe, col: c, row: r,
            axis, speed: 0.8 + (c % 3) * 0.3, range: BOARD_CELL * 0.9,
            basePos: new THREE.Vector3(x, WALL_HEIGHT / 2, z),
          });
          break;
        }
        case TILE.GRAVITY_SWITCH: {
          const gs = new THREE.Mesh(gravSwitchGeo, gravSwitchMat.clone());
          gs.position.set(x, 0.005, z);
          group.add(gs);
          const gg = new THREE.Mesh(gravGlowGeo, new THREE.MeshBasicMaterial({
            color: 0x00ff00, transparent: true, opacity: 0.2,
          }));
          gg.position.set(x, 0.02, z);
          group.add(gg);
          // Arrow indicator
          const arrow = new THREE.Mesh(
            new THREE.ConeGeometry(BOARD_CELL * 0.1, BOARD_CELL * 0.15, 4),
            new THREE.MeshBasicMaterial({ color: 0x00ff00, transparent: true, opacity: 0.5 })
          );
          arrow.position.set(x, 0.03, z);
          arrow.rotation.x = Math.PI; // pointing down (gravity)
          group.add(arrow);
          gravitySwitches.push({ mesh: gs, glowMesh: gg, col: c, row: r, cooldown: 0 });
          break;
        }
        case TILE.BUMPER: {
          const bm = new THREE.Mesh(bumperGeo, bumperMat.clone());
          bm.position.set(x, BOARD_CELL * 0.3, z);
          group.add(bm);
          const bg = new THREE.Mesh(bumperGlowGeo, new THREE.MeshBasicMaterial({
            color: 0xff66ff, transparent: true, opacity: 0.2,
          }));
          bg.position.copy(bm.position);
          group.add(bg);
          // Ring at base
          const bRing = new THREE.Mesh(
            new THREE.TorusGeometry(BOARD_CELL * 0.32, 0.003, 8, 24),
            new THREE.MeshBasicMaterial({ color: 0xff66ff, transparent: true, opacity: 0.6 })
          );
          bRing.position.set(x, 0.002, z);
          bRing.rotation.x = -Math.PI / 2;
          group.add(bRing);
          bumpers.push({ mesh: bm, glowMesh: bg, col: c, row: r });
          break;
        }
      }
    }
  }

  return {
    group, floor, walls, holes, gems, goalMesh,
    startPos, goalPos, teleA, teleB, teleMeshA, teleMeshB,
    iceTiles, boostTiles, powerups, movingWalls, gravitySwitches, bumpers, gridW, gridH, grid
  };
}

// Convert grid coords to local board position
export function gridToLocal(col: number, row: number, gridW: number, gridH: number): THREE.Vector3 {
  const bw = gridW * BOARD_CELL;
  const bh = gridH * BOARD_CELL;
  return new THREE.Vector3(
    col * BOARD_CELL - bw / 2 + BOARD_CELL / 2,
    MARBLE_RADIUS + 0.002,
    row * BOARD_CELL - bh / 2 + BOARD_CELL / 2
  );
}

// Get tile at world-local position on the board
export function getTileAt(x: number, z: number, gridW: number, gridH: number, grid: number[][]): TileType {
  const bw = gridW * BOARD_CELL;
  const bh = gridH * BOARD_CELL;
  const col = Math.floor((x + bw / 2) / BOARD_CELL);
  const row = Math.floor((z + bh / 2) / BOARD_CELL);
  if (row < 0 || row >= gridH || col < 0 || col >= gridW) return TILE.WALL;
  return grid[row][col] as TileType;
}

// Check if marble collides with walls, return push-out vector
export function checkWallCollision(
  mx: number, mz: number, grid: number[][], gridW: number, gridH: number
): THREE.Vector2 | null {
  const bw = gridW * BOARD_CELL;
  const bh = gridH * BOARD_CELL;
  const col = Math.floor((mx + bw / 2) / BOARD_CELL);
  const row = Math.floor((mz + bh / 2) / BOARD_CELL);

  const pushOut = new THREE.Vector2(0, 0);
  let collided = false;

  // Check neighbors and self
  for (let dr = -1; dr <= 1; dr++) {
    for (let dc = -1; dc <= 1; dc++) {
      const r = row + dr;
      const c = col + dc;
      if (r < 0 || r >= gridH || c < 0 || c >= gridW) continue;
      if (grid[r][c] !== TILE.WALL) continue;

      // Wall cell center
      const wx = c * BOARD_CELL - bw / 2 + BOARD_CELL / 2;
      const wz = r * BOARD_CELL - bh / 2 + BOARD_CELL / 2;
      const hw = BOARD_CELL * 0.475;  // half wall size

      // Closest point on wall box to marble center
      const cx = Math.max(wx - hw, Math.min(mx, wx + hw));
      const cz = Math.max(wz - hw, Math.min(mz, wz + hw));
      const dx = mx - cx;
      const dz = mz - cz;
      const dist = Math.sqrt(dx * dx + dz * dz);

      if (dist < MARBLE_RADIUS && dist > 0.0001) {
        const overlap = MARBLE_RADIUS - dist;
        pushOut.x += (dx / dist) * overlap;
        pushOut.y += (dz / dist) * overlap;
        collided = true;
      }
    }
  }

  return collided ? pushOut : null;
}

// Animate board objects (gems rotate, goal pulses, teleporters spin, power-ups float)
export function animateBoard(board: BoardObjects, time: number) {
  for (const gem of board.gems) {
    if (gem.visible) {
      gem.rotation.y = time * 2;
      gem.rotation.x = Math.sin(time * 3) * 0.3;
      gem.position.y = BOARD_CELL * 0.2 + Math.sin(time * 2.5) * 0.005;
    }
  }
  if (board.goalMesh) {
    board.goalMesh.rotation.z = time * 1.5;
    const s = 1 + Math.sin(time * 3) * 0.1;
    board.goalMesh.scale.set(s, s, s);
  }
  if (board.teleMeshA) board.teleMeshA.rotation.z = time * 2;
  if (board.teleMeshB) board.teleMeshB.rotation.z = -time * 2;
  for (const ice of board.iceTiles) {
    (ice.material as THREE.MeshStandardMaterial).opacity = 0.4 + Math.sin(time * 1.5) * 0.1;
  }
  for (const bt of board.boostTiles) {
    (bt.mesh.material as THREE.MeshStandardMaterial).opacity = 0.5 + Math.sin(time * 4) * 0.15;
  }
  // Power-ups: float and rotate
  for (const pu of board.powerups) {
    if (!pu.collected) {
      pu.mesh.rotation.y = time * 2.5;
      pu.mesh.position.y = BOARD_CELL * 0.25 + Math.sin(time * 3 + pu.col) * 0.008;
      pu.glowMesh.position.y = pu.mesh.position.y;
      const gs = 1 + Math.sin(time * 4) * 0.15;
      pu.glowMesh.scale.set(gs, gs, gs);
    }
  }
  // Moving walls: oscillate along axis
  for (const mw of board.movingWalls) {
    const offset = Math.sin(time * mw.speed) * mw.range;
    if (mw.axis === 'x') {
      mw.mesh.position.x = mw.basePos.x + offset;
      mw.edgeMesh.position.x = mw.basePos.x + offset;
    } else {
      mw.mesh.position.z = mw.basePos.z + offset;
      mw.edgeMesh.position.z = mw.basePos.z + offset;
    }
  }
  // Gravity switches: pulse glow
  for (const gs of board.gravitySwitches) {
    const pulse = 0.15 + Math.sin(time * 3 + gs.col * 2) * 0.1;
    (gs.glowMesh.material as THREE.MeshBasicMaterial).opacity = pulse;
    gs.glowMesh.scale.setScalar(1 + Math.sin(time * 2) * 0.15);
  }
  // Bumpers: bob and pulse
  for (const b of board.bumpers) {
    b.mesh.position.y = BOARD_CELL * 0.3 + Math.sin(time * 3 + b.col + b.row) * 0.005;
    const s = 1 + Math.sin(time * 4 + b.col * 1.5) * 0.08;
    b.mesh.scale.set(s, s, s);
    (b.glowMesh.material as THREE.MeshBasicMaterial).opacity = 0.15 + Math.sin(time * 5 + b.row) * 0.1;
    b.glowMesh.position.y = b.mesh.position.y;
  }
}

// effects.ts — Particle effects, trails, visual feedback
import * as THREE from 'three';

// Particle system with object pool
interface Particle {
  mesh: THREE.Mesh;
  vel: THREE.Vector3;
  life: number;
  maxLife: number;
}

export class ParticleSystem {
  private particles: Particle[] = [];
  private pool: Particle[] = [];
  private group: THREE.Group;
  private geo: THREE.SphereGeometry;
  private maxParticles = 80;

  constructor(parent: THREE.Object3D) {
    this.group = new THREE.Group();
    parent.add(this.group);
    this.geo = new THREE.SphereGeometry(0.006, 4, 4);

    for (let i = 0; i < this.maxParticles; i++) {
      const mat = new THREE.MeshBasicMaterial({ color: 0xffffff, transparent: true, opacity: 1 });
      const mesh = new THREE.Mesh(this.geo, mat);
      mesh.visible = false;
      this.group.add(mesh);
      this.pool.push({ mesh, vel: new THREE.Vector3(), life: 0, maxLife: 1 });
    }
  }

  burst(pos: THREE.Vector3, color: number, count: number, speed: number = 0.5, life: number = 0.8) {
    for (let i = 0; i < count; i++) {
      const p = this.pool.pop();
      if (!p) break;
      p.mesh.position.copy(pos);
      p.vel.set(
        (Math.random() - 0.5) * speed,
        Math.random() * speed * 0.8 + speed * 0.2,
        (Math.random() - 0.5) * speed
      );
      p.life = life;
      p.maxLife = life;
      p.mesh.visible = true;
      (p.mesh.material as THREE.MeshBasicMaterial).color.setHex(color);
      (p.mesh.material as THREE.MeshBasicMaterial).opacity = 1;
      this.particles.push(p);
    }
  }

  update(dt: number) {
    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];
      p.life -= dt;
      if (p.life <= 0) {
        p.mesh.visible = false;
        this.pool.push(p);
        this.particles.splice(i, 1);
        continue;
      }
      p.vel.y -= 1.5 * dt; // gravity
      p.mesh.position.addScaledVector(p.vel, dt);
      const t = p.life / p.maxLife;
      (p.mesh.material as THREE.MeshBasicMaterial).opacity = t;
      const s = 0.5 + t * 0.5;
      p.mesh.scale.set(s, s, s);
    }
  }
}

// Marble trail
export class TrailSystem {
  private points: THREE.Vector3[] = [];
  private line: THREE.Line;
  private maxPoints = 30;
  private geo: THREE.BufferGeometry;

  // Skin trail particles
  private trailParticles: { mesh: THREE.Mesh; vel: THREE.Vector3; life: number; maxLife: number }[] = [];
  private trailParticlePool: { mesh: THREE.Mesh; vel: THREE.Vector3; life: number; maxLife: number }[] = [];
  private trailGroup: THREE.Group;
  private trailGeo: THREE.SphereGeometry;
  private emitTimer = 0;

  // Skin trail config
  private trailStyle = 'default';
  private particleColor = 0x00ffff;
  private particleRate = 8;     // particles per second
  private trailOpacity = 0.5;
  private maxTrailParticles = 40;

  constructor(parent: THREE.Object3D, color: number, trailStyle: string = 'default', particleColor: number = 0x00ffff, particleRate: number = 8, trailWidth: number = 1.0) {
    this.geo = new THREE.BufferGeometry();
    const positions = new Float32Array(this.maxPoints * 3);
    this.geo.setAttribute('position', new THREE.BufferAttribute(positions, 3));
    this.geo.setDrawRange(0, 0);
    this.trailOpacity = 0.5 * trailWidth;
    const mat = new THREE.LineBasicMaterial({ color, transparent: true, opacity: this.trailOpacity });
    this.line = new THREE.Line(this.geo, mat);
    parent.add(this.line);

    // Trail particle system
    this.trailStyle = trailStyle;
    this.particleColor = particleColor;
    this.particleRate = particleRate;
    this.trailGroup = new THREE.Group();
    parent.add(this.trailGroup);

    // Particle geometry varies by style
    this.trailGeo = new THREE.SphereGeometry(this.getParticleSize(), 4, 4);

    // Pre-allocate trail particles
    for (let i = 0; i < this.maxTrailParticles; i++) {
      const mat = new THREE.MeshBasicMaterial({
        color: particleColor,
        transparent: true,
        opacity: 0.8,
      });
      const mesh = new THREE.Mesh(this.trailGeo, mat);
      mesh.visible = false;
      this.trailGroup.add(mesh);
      this.trailParticlePool.push({ mesh, vel: new THREE.Vector3(), life: 0, maxLife: 1 });
    }
  }

  private getParticleSize(): number {
    switch (this.trailStyle) {
      case 'fire': return 0.005;
      case 'frost': return 0.004;
      case 'toxic': return 0.006;
      case 'void': return 0.007;
      case 'obsidian': return 0.004;
      case 'diamond': return 0.003;
      case 'nebula': return 0.006;
      case 'gold': return 0.005;
      case 'chrome': return 0.003;
      case 'emerald': return 0.004;
      case 'royal': return 0.005;
      default: return 0.004;
    }
  }

  addPoint(pos: THREE.Vector3) {
    this.points.push(pos.clone());
    if (this.points.length > this.maxPoints) this.points.shift();
    const attr = this.geo.getAttribute('position') as THREE.BufferAttribute;
    for (let i = 0; i < this.points.length; i++) {
      attr.setXYZ(i, this.points[i].x, this.points[i].y, this.points[i].z);
    }
    attr.needsUpdate = true;
    this.geo.setDrawRange(0, this.points.length);
  }

  // Emit trail particles based on skin style
  emitTrailParticle(pos: THREE.Vector3, speed: number) {
    if (this.trailStyle === 'default' && this.particleRate <= 8) return; // default skin: minimal particles
    if (speed < 0.3) return; // Don't emit when barely moving

    const p = this.trailParticlePool.pop();
    if (!p) return;

    p.mesh.position.copy(pos);
    const mat = p.mesh.material as THREE.MeshBasicMaterial;
    mat.color.setHex(this.particleColor);

    switch (this.trailStyle) {
      case 'fire': {
        // Embers that rise and fade
        p.vel.set(
          (Math.random() - 0.5) * 0.15,
          Math.random() * 0.25 + 0.1,
          (Math.random() - 0.5) * 0.15
        );
        p.life = 0.5 + Math.random() * 0.4;
        // Randomize between orange/red
        mat.color.setHex(Math.random() > 0.5 ? 0xff6600 : 0xff2200);
        break;
      }
      case 'frost': {
        // Crystalline sparkles that drift slowly
        p.vel.set(
          (Math.random() - 0.5) * 0.08,
          Math.random() * 0.05 + 0.02,
          (Math.random() - 0.5) * 0.08
        );
        p.life = 0.8 + Math.random() * 0.5;
        mat.color.setHex(Math.random() > 0.3 ? 0xccddff : 0x88bbff);
        break;
      }
      case 'toxic': {
        // Green wisps that swirl
        const angle = Math.random() * Math.PI * 2;
        p.vel.set(
          Math.cos(angle) * 0.12,
          Math.random() * 0.15 + 0.05,
          Math.sin(angle) * 0.12
        );
        p.life = 0.6 + Math.random() * 0.3;
        break;
      }
      case 'void': {
        // Dark particles that implode inward slightly
        p.vel.set(
          (Math.random() - 0.5) * 0.05,
          -Math.random() * 0.1 - 0.02,
          (Math.random() - 0.5) * 0.05
        );
        p.life = 0.7 + Math.random() * 0.4;
        mat.color.setHex(Math.random() > 0.4 ? 0x6622aa : 0x440088);
        break;
      }
      case 'gold': {
        // Golden shimmer sparks
        p.vel.set(
          (Math.random() - 0.5) * 0.2,
          Math.random() * 0.2 + 0.08,
          (Math.random() - 0.5) * 0.2
        );
        p.life = 0.4 + Math.random() * 0.3;
        mat.color.setHex(Math.random() > 0.5 ? 0xffdd44 : 0xffaa00);
        break;
      }
      case 'diamond': {
        // Prismatic sparkles — cycle colors
        const colors = [0xddeeff, 0xffddee, 0xddffee, 0xeeddff];
        mat.color.setHex(colors[Math.floor(Math.random() * colors.length)]);
        p.vel.set(
          (Math.random() - 0.5) * 0.1,
          Math.random() * 0.12 + 0.05,
          (Math.random() - 0.5) * 0.1
        );
        p.life = 0.6 + Math.random() * 0.4;
        break;
      }
      case 'nebula': {
        // Swirling pink/magenta clouds
        const a = Math.random() * Math.PI * 2;
        p.vel.set(
          Math.cos(a) * 0.15,
          (Math.random() - 0.5) * 0.1,
          Math.sin(a) * 0.15
        );
        p.life = 0.7 + Math.random() * 0.5;
        mat.color.setHex(Math.random() > 0.5 ? 0xff66cc : 0xdd2288);
        break;
      }
      case 'obsidian': {
        // Dark red embers that crackle
        p.vel.set(
          (Math.random() - 0.5) * 0.18,
          Math.random() * 0.15 + 0.05,
          (Math.random() - 0.5) * 0.18
        );
        p.life = 0.3 + Math.random() * 0.3;
        mat.color.setHex(Math.random() > 0.6 ? 0xaa0055 : 0x660022);
        break;
      }
      case 'chrome': {
        // Sharp white sparks
        p.vel.set(
          (Math.random() - 0.5) * 0.25,
          Math.random() * 0.1 + 0.05,
          (Math.random() - 0.5) * 0.25
        );
        p.life = 0.25 + Math.random() * 0.2;
        break;
      }
      case 'emerald': {
        // Green gem dust
        p.vel.set(
          (Math.random() - 0.5) * 0.12,
          Math.random() * 0.1 + 0.04,
          (Math.random() - 0.5) * 0.12
        );
        p.life = 0.5 + Math.random() * 0.4;
        mat.color.setHex(Math.random() > 0.5 ? 0x44ee88 : 0x22cc44);
        break;
      }
      case 'royal': {
        // Purple sparkle stars
        p.vel.set(
          (Math.random() - 0.5) * 0.15,
          Math.random() * 0.18 + 0.06,
          (Math.random() - 0.5) * 0.15
        );
        p.life = 0.5 + Math.random() * 0.3;
        mat.color.setHex(Math.random() > 0.5 ? 0xdd88ff : 0xaa44ff);
        break;
      }
      default: {
        // Default cyan particles
        p.vel.set(
          (Math.random() - 0.5) * 0.08,
          Math.random() * 0.08 + 0.03,
          (Math.random() - 0.5) * 0.08
        );
        p.life = 0.5;
        break;
      }
    }

    p.maxLife = p.life;
    p.mesh.visible = true;
    mat.opacity = 0.8;
    this.trailParticles.push(p);
  }

  updateParticles(dt: number, marblePos: THREE.Vector3, speed: number) {
    // Emit new particles
    this.emitTimer += dt;
    const emitInterval = 1 / this.particleRate;
    while (this.emitTimer >= emitInterval) {
      this.emitTimer -= emitInterval;
      this.emitTrailParticle(marblePos, speed);
    }

    // Update existing particles
    for (let i = this.trailParticles.length - 1; i >= 0; i--) {
      const p = this.trailParticles[i];
      p.life -= dt;
      if (p.life <= 0) {
        p.mesh.visible = false;
        this.trailParticlePool.push(p);
        this.trailParticles.splice(i, 1);
        continue;
      }

      // Style-specific movement
      if (this.trailStyle === 'void') {
        // Void particles contract slightly
        p.vel.multiplyScalar(0.95);
      } else if (this.trailStyle === 'fire') {
        // Fire particles slow + gravity resist
        p.vel.y *= 0.98;
      } else {
        // Standard gravity effect
        p.vel.y -= 0.3 * dt;
      }

      p.mesh.position.addScaledVector(p.vel, dt);
      const t = p.life / p.maxLife;
      (p.mesh.material as THREE.MeshBasicMaterial).opacity = t * 0.8;
      const s = 0.4 + t * 0.6;
      p.mesh.scale.set(s, s, s);
    }
  }

  clear() {
    this.points = [];
    this.geo.setDrawRange(0, 0);
    // Clear trail particles
    for (const p of this.trailParticles) {
      p.mesh.visible = false;
      this.trailParticlePool.push(p);
    }
    this.trailParticles = [];
    this.emitTimer = 0;
  }

  setColor(color: number) {
    (this.line.material as THREE.LineBasicMaterial).color.setHex(color);
  }
}

// Ambient floating particles for the holodeck environment
export class AmbientParticles {
  private meshes: THREE.Mesh[] = [];
  private velocities: THREE.Vector3[] = [];
  private group: THREE.Group;

  constructor(parent: THREE.Object3D, count: number = 40, range: number = 3) {
    this.group = new THREE.Group();
    parent.add(this.group);
    const geo = new THREE.SphereGeometry(0.008, 4, 4);

    for (let i = 0; i < count; i++) {
      const mat = new THREE.MeshBasicMaterial({
        color: 0x00ffff,
        transparent: true,
        opacity: 0.2 + Math.random() * 0.3,
      });
      const mesh = new THREE.Mesh(geo, mat);
      mesh.position.set(
        (Math.random() - 0.5) * range,
        Math.random() * range * 0.5 + 0.5,
        (Math.random() - 0.5) * range
      );
      this.group.add(mesh);
      this.meshes.push(mesh);
      this.velocities.push(new THREE.Vector3(
        (Math.random() - 0.5) * 0.02,
        (Math.random() - 0.5) * 0.01,
        (Math.random() - 0.5) * 0.02
      ));
    }
  }

  update(time: number) {
    for (let i = 0; i < this.meshes.length; i++) {
      const m = this.meshes[i];
      m.position.addScaledVector(this.velocities[i], 1);
      m.position.y += Math.sin(time * 0.5 + i) * 0.0003;
      (m.material as THREE.MeshBasicMaterial).opacity = 0.2 + Math.sin(time + i * 0.7) * 0.15;
    }
  }
}

// Holodeck wireframe decorations
export function createHolodeckDecorations(parent: THREE.Object3D, count: number = 12): THREE.Object3D[] {
  const decos: THREE.Object3D[] = [];
  const geos = [
    new THREE.TorusGeometry(0.1, 0.02, 6, 12),
    new THREE.BoxGeometry(0.12, 0.12, 0.12),
    new THREE.SphereGeometry(0.08, 6, 6),
    new THREE.ConeGeometry(0.07, 0.14, 6),
  ];

  for (let i = 0; i < count; i++) {
    const geo = geos[i % geos.length];
    const mat = new THREE.MeshBasicMaterial({
      color: 0x00ffff,
      wireframe: true,
      transparent: true,
      opacity: 0.15 + Math.random() * 0.1,
    });
    const mesh = new THREE.Mesh(geo, mat);
    const angle = (i / count) * Math.PI * 2;
    const radius = 1.5 + Math.random();
    mesh.position.set(
      Math.cos(angle) * radius,
      0.5 + Math.random() * 1.5,
      Math.sin(angle) * radius
    );
    mesh.rotation.set(Math.random() * Math.PI, Math.random() * Math.PI, 0);
    parent.add(mesh);
    decos.push(mesh);
  }
  return decos;
}

export function animateDecorations(decos: THREE.Object3D[], time: number) {
  for (let i = 0; i < decos.length; i++) {
    decos[i].rotation.y = time * 0.3 + i;
    decos[i].rotation.x = Math.sin(time * 0.2 + i) * 0.5;
    decos[i].position.y += Math.sin(time * 0.4 + i * 0.5) * 0.0002;
  }
}

// audio.ts — Procedural Web Audio manager for Neon Marble VR
// Zone-based synthwave music with crossfade transitions

interface ZoneTrack {
  oscs: OscillatorNode[];
  gains: GainNode[];
  masterGain: GainNode;
}

export class AudioManager {
  private ctx: AudioContext | null = null;
  private master: GainNode | null = null;
  private sfxGain: GainNode | null = null;
  private musicGain: GainNode | null = null;
  private musicStarted = false;

  // Zone music system
  private currentZone = -1;
  private currentTrack: ZoneTrack | null = null;
  private fadingTrack: ZoneTrack | null = null;
  private fadeTimer = 0;
  private fadeDuration = 1.5; // seconds for crossfade

  sfxVolume = 0.7;
  musicVolume = 0.3;
  masterVolume = 0.8;

  private ensureCtx(): AudioContext {
    if (!this.ctx) {
      this.ctx = new AudioContext();
      this.master = this.ctx.createGain();
      this.master.gain.value = this.masterVolume;
      this.master.connect(this.ctx.destination);
      this.sfxGain = this.ctx.createGain();
      this.sfxGain.gain.value = this.sfxVolume;
      this.sfxGain.connect(this.master);
      this.musicGain = this.ctx.createGain();
      this.musicGain.gain.value = this.musicVolume;
      this.musicGain.connect(this.master);
    }
    if (this.ctx.state === 'suspended') this.ctx.resume();
    return this.ctx;
  }

  setMasterVolume(v: number) { this.masterVolume = v; if (this.master) this.master.gain.value = v; }
  setSfxVolume(v: number) { this.sfxVolume = v; if (this.sfxGain) this.sfxGain.gain.value = v; }
  setMusicVolume(v: number) { this.musicVolume = v; if (this.musicGain) this.musicGain.gain.value = v; }

  startMusic() {
    if (this.musicStarted) return;
    const ctx = this.ensureCtx();
    if (!this.musicGain) return;
    this.musicStarted = true;
    this.setZone(0); // Start with Classic zone
  }

  stopMusic() {
    this.stopTrack(this.currentTrack);
    this.stopTrack(this.fadingTrack);
    this.currentTrack = null;
    this.fadingTrack = null;
    this.currentZone = -1;
    this.musicStarted = false;
  }

  private stopTrack(track: ZoneTrack | null) {
    if (!track) return;
    try {
      for (const osc of track.oscs) { try { osc.stop(); } catch {} }
      track.masterGain.disconnect();
    } catch {}
  }

  // Create a zone-specific synthwave track
  private createZoneTrack(zone: number): ZoneTrack {
    const ctx = this.ensureCtx();
    const trackGain = ctx.createGain();
    trackGain.gain.value = 0; // Start silent for crossfade
    trackGain.connect(this.musicGain!);

    const oscs: OscillatorNode[] = [];
    const gains: GainNode[] = [];

    // Zone-specific musical parameters
    const configs = [
      // Zone 0 - Classic: Calm, atmospheric — C minor ambient
      {
        layers: [
          { type: 'sine' as OscillatorType, freq: 65.41, gain: 0.12, detune: 0 },      // C2 bass drone
          { type: 'triangle' as OscillatorType, freq: 130.81, gain: 0.06, detune: 3 },  // C3 octave
          { type: 'sine' as OscillatorType, freq: 155.56, gain: 0.05, detune: -2 },     // Eb3 minor color
          { type: 'sine' as OscillatorType, freq: 196.0, gain: 0.04, detune: 5 },       // G3 fifth
        ],
        lfoRate: 0.12,
        lfoDepth: 0.03,
        filterFreq: 800,
      },
      // Zone 1 - Power-Up: Driving, energetic — F minor
      {
        layers: [
          { type: 'sawtooth' as OscillatorType, freq: 87.31, gain: 0.08, detune: 0 },   // F2 bass
          { type: 'square' as OscillatorType, freq: 174.61, gain: 0.04, detune: 7 },    // F3
          { type: 'triangle' as OscillatorType, freq: 207.65, gain: 0.05, detune: -3 }, // Ab3 minor
          { type: 'sine' as OscillatorType, freq: 261.63, gain: 0.04, detune: 5 },      // C4 fifth
          { type: 'square' as OscillatorType, freq: 349.23, gain: 0.02, detune: -5 },   // F4 octave shimmer
        ],
        lfoRate: 0.25,
        lfoDepth: 0.04,
        filterFreq: 1200,
      },
      // Zone 2 - Endgame: Intense, dark — D minor
      {
        layers: [
          { type: 'sawtooth' as OscillatorType, freq: 73.42, gain: 0.10, detune: 0 },   // D2 bass
          { type: 'sawtooth' as OscillatorType, freq: 146.83, gain: 0.05, detune: -8 }, // D3 detuned
          { type: 'triangle' as OscillatorType, freq: 174.61, gain: 0.06, detune: 3 },  // F3 minor
          { type: 'sine' as OscillatorType, freq: 220.0, gain: 0.04, detune: 0 },       // A3 fifth
          { type: 'sawtooth' as OscillatorType, freq: 293.66, gain: 0.02, detune: 12 }, // D4 high
        ],
        lfoRate: 0.35,
        lfoDepth: 0.05,
        filterFreq: 1000,
      },
      // Zone 3 - Bumper: Funky, bouncy — G minor
      {
        layers: [
          { type: 'square' as OscillatorType, freq: 98.0, gain: 0.08, detune: 0 },      // G2 bass
          { type: 'triangle' as OscillatorType, freq: 196.0, gain: 0.06, detune: 5 },   // G3
          { type: 'sine' as OscillatorType, freq: 233.08, gain: 0.05, detune: -4 },     // Bb3 minor
          { type: 'square' as OscillatorType, freq: 293.66, gain: 0.03, detune: 8 },    // D4 fifth
        ],
        lfoRate: 0.4,
        lfoDepth: 0.06,
        filterFreq: 1500,
      },
      // Zone 4 - Master: Epic, full — E minor
      {
        layers: [
          { type: 'sawtooth' as OscillatorType, freq: 82.41, gain: 0.10, detune: 0 },   // E2 bass
          { type: 'sawtooth' as OscillatorType, freq: 164.81, gain: 0.06, detune: -5 }, // E3
          { type: 'triangle' as OscillatorType, freq: 196.0, gain: 0.05, detune: 3 },   // G3 minor
          { type: 'sine' as OscillatorType, freq: 246.94, gain: 0.04, detune: 0 },      // B3 fifth
          { type: 'square' as OscillatorType, freq: 329.63, gain: 0.03, detune: 7 },    // E4 octave
          { type: 'sine' as OscillatorType, freq: 493.88, gain: 0.02, detune: -3 },     // B4 high shimmer
        ],
        lfoRate: 0.2,
        lfoDepth: 0.04,
        filterFreq: 1400,
      },
    ];

    const cfg = configs[zone] || configs[0];

    // Shared filter for the zone
    const filter = ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = cfg.filterFreq;
    filter.Q.value = 1.5;
    filter.connect(trackGain);

    // Create oscillator layers
    for (const layer of cfg.layers) {
      const osc = ctx.createOscillator();
      osc.type = layer.type;
      osc.frequency.value = layer.freq;
      osc.detune.value = layer.detune;
      const g = ctx.createGain();
      g.gain.value = layer.gain;
      osc.connect(g);
      g.connect(filter);
      osc.start();
      oscs.push(osc);
      gains.push(g);
    }

    // LFO modulating filter cutoff for movement
    const lfo = ctx.createOscillator();
    lfo.type = 'sine';
    lfo.frequency.value = cfg.lfoRate;
    const lfoGain = ctx.createGain();
    lfoGain.gain.value = cfg.filterFreq * cfg.lfoDepth;
    lfo.connect(lfoGain);
    lfoGain.connect(filter.frequency);
    lfo.start();
    oscs.push(lfo);
    gains.push(lfoGain);

    // Second LFO for slow volume swell
    const lfo2 = ctx.createOscillator();
    lfo2.type = 'sine';
    lfo2.frequency.value = cfg.lfoRate * 0.5;
    const lfo2Gain = ctx.createGain();
    lfo2Gain.gain.value = 0.02;
    lfo2.connect(lfo2Gain);
    // Modulate the first oscillator's gain for breathing effect
    if (gains.length > 0) {
      lfo2Gain.connect(gains[0].gain);
    }
    lfo2.start();
    oscs.push(lfo2);
    gains.push(lfo2Gain);

    return { oscs, gains, masterGain: trackGain };
  }

  // Set the active music zone with crossfade
  setZone(zone: number) {
    if (!this.musicStarted) return;
    if (zone === this.currentZone) return;
    const ctx = this.ensureCtx();
    if (!this.musicGain) return;

    // Stop any existing fade
    if (this.fadingTrack) {
      this.stopTrack(this.fadingTrack);
      this.fadingTrack = null;
    }

    // Move current track to fading out
    if (this.currentTrack) {
      this.fadingTrack = this.currentTrack;
      // Fade out old track
      this.fadingTrack.masterGain.gain.setValueAtTime(
        this.fadingTrack.masterGain.gain.value, ctx.currentTime
      );
      this.fadingTrack.masterGain.gain.linearRampToValueAtTime(0, ctx.currentTime + this.fadeDuration);
      // Schedule cleanup
      const oldTrack = this.fadingTrack;
      setTimeout(() => {
        this.stopTrack(oldTrack);
        if (this.fadingTrack === oldTrack) this.fadingTrack = null;
      }, this.fadeDuration * 1000 + 100);
    }

    // Create and fade in new track
    this.currentZone = zone;
    this.currentTrack = this.createZoneTrack(zone);
    this.currentTrack.masterGain.gain.setValueAtTime(0, ctx.currentTime);
    this.currentTrack.masterGain.gain.linearRampToValueAtTime(1, ctx.currentTime + this.fadeDuration);
  }

  getCurrentZone(): number { return this.currentZone; }

  // --- SFX ---

  playRoll(speed: number) {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const noise = ctx.createOscillator();
    noise.type = 'sawtooth';
    noise.frequency.value = 200 + speed * 300;
    const g = ctx.createGain();
    g.gain.setValueAtTime(Math.min(speed * 0.08, 0.06), ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.05);
    const f = ctx.createBiquadFilter();
    f.type = 'lowpass';
    f.frequency.value = 400 + speed * 600;
    noise.connect(f);
    f.connect(g);
    g.connect(this.sfxGain);
    noise.start();
    noise.stop(ctx.currentTime + 0.05);
  }

  playBounce(intensity: number) {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const osc = ctx.createOscillator();
    osc.type = 'triangle';
    osc.frequency.setValueAtTime(300 + intensity * 200, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(100, ctx.currentTime + 0.1);
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.15, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.12);
    osc.connect(g);
    g.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.12);
  }

  playGemCollect() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const notes = [880, 1108, 1320];
    notes.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'sine';
      osc.frequency.value = freq;
      const g = ctx.createGain();
      g.gain.setValueAtTime(0, ctx.currentTime + i * 0.08);
      g.gain.linearRampToValueAtTime(0.12, ctx.currentTime + i * 0.08 + 0.02);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.08 + 0.15);
      osc.connect(g);
      g.connect(this.sfxGain!);
      osc.start(ctx.currentTime + i * 0.08);
      osc.stop(ctx.currentTime + i * 0.08 + 0.15);
    });
  }

  playFall() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const osc = ctx.createOscillator();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(600, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(80, ctx.currentTime + 0.5);
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.18, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.5);
    osc.connect(g);
    g.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.5);
  }

  playGoal() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const chord = [523, 659, 784, 1047];
    chord.forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'sine';
      osc.frequency.value = freq;
      const g = ctx.createGain();
      g.gain.setValueAtTime(0, ctx.currentTime + i * 0.1);
      g.gain.linearRampToValueAtTime(0.12, ctx.currentTime + i * 0.1 + 0.03);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.1 + 0.4);
      osc.connect(g);
      g.connect(this.sfxGain!);
      osc.start(ctx.currentTime + i * 0.1);
      osc.stop(ctx.currentTime + i * 0.1 + 0.4);
    });
  }

  playTeleport() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const osc = ctx.createOscillator();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(200, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(2000, ctx.currentTime + 0.15);
    osc.frequency.exponentialRampToValueAtTime(400, ctx.currentTime + 0.3);
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.12, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.35);
    const f = ctx.createBiquadFilter();
    f.type = 'bandpass';
    f.frequency.value = 1000;
    f.Q.value = 2;
    osc.connect(f);
    f.connect(g);
    g.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.35);
  }

  playBoost() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const osc = ctx.createOscillator();
    osc.type = 'square';
    osc.frequency.setValueAtTime(300, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(900, ctx.currentTime + 0.15);
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.1, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.2);
    osc.connect(g);
    g.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.2);
  }

  playButton() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const osc = ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.value = 660;
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.08, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.08);
    osc.connect(g);
    g.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.08);
  }

  playGameStart() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    [440, 554, 659].forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'sine';
      osc.frequency.value = freq;
      const g = ctx.createGain();
      g.gain.setValueAtTime(0, ctx.currentTime + i * 0.12);
      g.gain.linearRampToValueAtTime(0.1, ctx.currentTime + i * 0.12 + 0.02);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.12 + 0.2);
      osc.connect(g);
      g.connect(this.sfxGain!);
      osc.start(ctx.currentTime + i * 0.12);
      osc.stop(ctx.currentTime + i * 0.12 + 0.2);
    });
  }

  playGameOver() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    [440, 370, 311, 261].forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'triangle';
      osc.frequency.value = freq;
      const g = ctx.createGain();
      g.gain.setValueAtTime(0, ctx.currentTime + i * 0.15);
      g.gain.linearRampToValueAtTime(0.1, ctx.currentTime + i * 0.15 + 0.03);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.15 + 0.3);
      osc.connect(g);
      g.connect(this.sfxGain!);
      osc.start(ctx.currentTime + i * 0.15);
      osc.stop(ctx.currentTime + i * 0.15 + 0.3);
    });
  }

  playAchievement() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    [523, 659, 784, 1047, 1318].forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'sine';
      osc.frequency.value = freq;
      const g = ctx.createGain();
      g.gain.setValueAtTime(0, ctx.currentTime + i * 0.07);
      g.gain.linearRampToValueAtTime(0.09, ctx.currentTime + i * 0.07 + 0.02);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.07 + 0.25);
      osc.connect(g);
      g.connect(this.sfxGain!);
      osc.start(ctx.currentTime + i * 0.07);
      osc.stop(ctx.currentTime + i * 0.07 + 0.25);
    });
  }

  playCountdownTick() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const osc = ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.value = 880;
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.12, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.1);
    osc.connect(g);
    g.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.1);
  }

  playIceSlide() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const noise = ctx.createOscillator();
    noise.type = 'sawtooth';
    noise.frequency.value = 3000;
    const f = ctx.createBiquadFilter();
    f.type = 'highpass';
    f.frequency.value = 2000;
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.03, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.08);
    noise.connect(f);
    f.connect(g);
    g.connect(this.sfxGain);
    noise.start();
    noise.stop(ctx.currentTime + 0.08);
  }

  playPowerup(type: 'shield' | 'magnet' | 'slowmo') {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const baseFreq = type === 'shield' ? 440 : type === 'magnet' ? 550 : 660;
    const color = type === 'shield' ? 'sine' as OscillatorType : type === 'magnet' ? 'triangle' as OscillatorType : 'square' as OscillatorType;
    [baseFreq, baseFreq * 1.25, baseFreq * 1.5, baseFreq * 2].forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = color;
      osc.frequency.value = freq;
      const g = ctx.createGain();
      g.gain.setValueAtTime(0, ctx.currentTime + i * 0.06);
      g.gain.linearRampToValueAtTime(0.1, ctx.currentTime + i * 0.06 + 0.02);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.06 + 0.2);
      osc.connect(g);
      g.connect(this.sfxGain!);
      osc.start(ctx.currentTime + i * 0.06);
      osc.stop(ctx.currentTime + i * 0.06 + 0.2);
    });
  }

  playShieldBreak() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const osc = ctx.createOscillator();
    osc.type = 'sawtooth';
    osc.frequency.setValueAtTime(800, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(200, ctx.currentTime + 0.3);
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.15, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.35);
    const f = ctx.createBiquadFilter();
    f.type = 'lowpass';
    f.frequency.setValueAtTime(2000, ctx.currentTime);
    f.frequency.exponentialRampToValueAtTime(300, ctx.currentTime + 0.3);
    osc.connect(f);
    f.connect(g);
    g.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.35);
  }

  playMagnetPull() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const osc = ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(600, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(800, ctx.currentTime + 0.1);
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.06, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.12);
    osc.connect(g);
    g.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.12);
  }

  playBumper() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const osc = ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(200, ctx.currentTime);
    osc.frequency.exponentialRampToValueAtTime(800, ctx.currentTime + 0.06);
    osc.frequency.exponentialRampToValueAtTime(300, ctx.currentTime + 0.2);
    const g = ctx.createGain();
    g.gain.setValueAtTime(0.18, ctx.currentTime);
    g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.25);
    osc.connect(g);
    g.connect(this.sfxGain);
    osc.start();
    osc.stop(ctx.currentTime + 0.25);
    const sub = ctx.createOscillator();
    sub.type = 'sine';
    sub.frequency.value = 80;
    const sg = ctx.createGain();
    sg.gain.setValueAtTime(0.12, ctx.currentTime);
    sg.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.1);
    sub.connect(sg);
    sg.connect(this.sfxGain);
    sub.start();
    sub.stop(ctx.currentTime + 0.1);
  }

  playCombo(count: number) {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    const baseFreq = 600 + count * 100;
    [baseFreq, baseFreq * 1.25, baseFreq * 1.5].forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'sine';
      osc.frequency.value = freq;
      const g = ctx.createGain();
      g.gain.setValueAtTime(0, ctx.currentTime + i * 0.05);
      g.gain.linearRampToValueAtTime(0.1, ctx.currentTime + i * 0.05 + 0.02);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + i * 0.05 + 0.12);
      osc.connect(g);
      g.connect(this.sfxGain!);
      osc.start(ctx.currentTime + i * 0.05);
      osc.stop(ctx.currentTime + i * 0.05 + 0.12);
    });
  }

  playSplitGood() {
    const ctx = this.ensureCtx();
    if (!this.sfxGain) return;
    // Quick ascending chime for PB split
    [660, 880].forEach((freq, i) => {
      const osc = ctx.createOscillator();
      osc.type = 'sine';
